-- ---------- herbs (37) ----------
insert into public.herbs (herb_id, name_tr, gezegen_birincil, app_safe, guven_tier, data)
select
  e->>'herb_id',
  e#>>'{names,tr}',
  e->>'gezegen_birincil',
  coalesce((e#>>'{guvenlik,app_safe}')::boolean, true),
  e#>>'{guvenlik,guven_tier}',
  e
from jsonb_array_elements($wseed$[{"herb_id":"papatya","names":{"tr":"Papatya","en":"Chamomile","la":"Matricaria chamomilla"},"gezegen_birincil":"ay","gezegen_ikincil":["mars"],"celiski_notu":"Kaynaklarda Ay ve Mars eşit sıklıkta (9=9). Mars, papatyanın 'Marsik ısı/öfkeyi serinleten karşıt-bitki' olarak anıldığı ilişkisel bağlamdan gelir — kimlik değil. Botanik kimlik (yatıştırma, uyku, sindirim) Ay'a ait → birincil Ay.","beden_bolgeleri":["mide-sindirim","sinir-uyku"],"tat":["acımsı-tatlı"],"enerjetik":{"isi":"serinletici","nem":"provisional","durum":"kaynakta serinletici geçiyor; nem ekseni dogrulanamadi"},"mevsim":["yaz"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"T-listesinde yok; doğrulanmadı","not":"contraindications.json'da papatya kaydı yok. Bilinen papatya-ragweed (Asteraceae) alerji notu vault'ta YOK — eklenmesi Türkan kararı."},"kaynak_sayisi":17,"source_note":"Ay grubu (duygu/sıvı/üreme) ve Mars serinletici bağlamı birden çok kaynakta.","mevsim_tipi":"botanik","tek_satir":"Ay'ın yumuşak nefesi; telaşın karşısına sessizlikle çıkan çiçek.","story_narrative":"Papatya, geleneksel bitki kültüründe Ay'ın çevresinde anılan bitkilerdendir — akşamın, dinlenmenin ve suların çiçeği. Küçük ve sade görünür; telaşın karşısına sessiz bir duruşla çıkar.\n\nEski metinlerde serinliğin ve yumuşaklığın tarafında yazılmış; bu yönüyle nezaketin ve dengenin sembolü sayılmıştır.","ritual":"Akşam, papatya illüstrasyonuna bakarken üç yavaş nefes al. Günün taşıdığın telaşını, her nefes verişte biraz daha bırakmaya niyet et. İstersen bir papatyayı pencere kenarında büyüt; ona bakışın, güne verdiğin küçük bir molanın işareti olsun."},{"herb_id":"rezene","names":{"tr":"Rezene","en":"Fennel","la":"Foeniculum vulgare"},"gezegen_birincil":"merkur","gezegen_ikincil":["ay","venus"],"celiski_notu":null,"beden_bolgeleri":["mide-sindirim","gogus-nefes"],"tat":["tatlımsı"],"enerjetik":{"isi":"ısıtıcı-hafif","nem":"provisional","durum":"dogrulanamadi"},"mevsim":["yaz","sonbahar"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"doğrulanmadı","not":"T-listesinde yok."},"kaynak_sayisi":18,"source_note":"Merkür (iletişim/sinir/sindirim) grubunda net; en yüksek frekans (17 Merkür).","mevsim_tipi":"botanik","tek_satir":"Merkür'ün hafif adımı; söze ve güne ferahlık getiren tohum.","story_narrative":"Rezene, geleneksel metinlerde Merkür'ün bitkileri arasında sayılır — hareketin ve anlatmanın gezegeninin. İnce dallı, hafif kokulu yapısıyla ağırlığı değil akışkanlığı çağrıştırır.\n\nEski bahçe kültüründe sofraların ve konuşmaların kıyısında kendine hep bir yer bulmuş; hafifliğin sessiz temsilcisi olmuştur.","ritual":"Bugün söyleyeceğin önemli bir söz varsa, önce bir an dur. Rezenenin ince dallarını gözünde canlandır ve 'sözlerime hafiflik' diye içinden geçir. Konuşma, yük taşımak zorunda değil; akabilir de."},{"herb_id":"zencefil","names":{"tr":"Zencefil","en":"Ginger","la":"Zingiber officinale"},"gezegen_birincil":"mars","gezegen_ikincil":["saturn"],"celiski_notu":"Mars (13) ≈ Satürn (12). Satürn, zencefilin 'soğuk-nemli/balgama karşı ısıtıcı' olarak anıldığı ilişkisel bağlamdan gelir. Kimlik (ısı, dolaşım, inflamasyon) Mars → birincil Mars.","beden_bolgeleri":["mide-sindirim","kalp-dolasim"],"tat":["keskin"],"enerjetik":{"isi":"ısıtıcı","nem":"kurutucu","durum":"kaynakta 'kurutucu-ısıtıcı' açıkça geçiyor"},"mevsim":["her-mevsim"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"doğrulanmadı","not":"T-listesinde yok; bilinen antikoagülan etkileşimi vault'ta YOK — Türkan kararı."},"kaynak_sayisi":18,"source_note":"Mars (enerji/inflamasyon/kas) ve Satürn karşıt-ısıtıcı bağlamı.","mevsim_tipi":"geleneksel-sembolik","tek_satir":"Mars'ın iç ateşi; harekete geçiren kök.","story_narrative":"Zencefil, geleneksel gelenekte Mars'ın sıcak ve uyandırıcı bitkileri arasında anılır. Toprağın altında sessizce güç biriktiren bir kök; keskin kokusuyla durgunluğa itiraz eder.\n\nEski metinlerde soğuğa ve ağırlığa karşı içsel ateşi çağıran bir imge olarak geçer — cesaretin ve ilk adımın bitkisi.","ritual":"Sabah, ertelediğin bir işi düşün. Taze zencefilin keskin kokusunu hayal et — ya da mutfağındaysa bir an kokla. Sonra o işe atacağın en küçük ilk adımı seç. Ateş, kıvılcımla başlar."},{"herb_id":"karahindiba","names":{"tr":"Karahindiba","en":"Dandelion","la":"Taraxacum officinale"},"gezegen_birincil":"jupiter","gezegen_ikincil":["saturn"],"celiski_notu":null,"beden_bolgeleri":["karaciger","bobrek-mesane"],"tat":["acı"],"enerjetik":{"isi":"provisional","nem":"provisional","durum":"dogrulanamadi"},"mevsim":["ilkbahar"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"doğrulanmadı","not":"T-listesinde yok."},"kaynak_sayisi":16,"source_note":"Jüpiter (karaciğer/kan/genişleme/metabolizma) grubunda net (13).","mevsim_tipi":"botanik","tek_satir":"Jüpiter'in cömert tohumu; dileği rüzgâra emanet eden çiçek.","story_narrative":"Karahindiba, geleneksel metinlerde Jüpiter'in genişleten ve cömert bitkileri arasında sayılır. Sarı çiçeği güneşe, tohum küresi rüzgâra aittir — biriktirmeyi değil dağıtmayı bilir.\n\nEski bitki kültüründe baharın habercilerinden sayılmış; yenilenmenin ve yeniden başlamanın sade bir simgesi olmuştur.","ritual":"Bir karahindiba tohum küresi hayal et. Bu ay büyümesini istediğin bir niyeti içinden söyle ve tohumları rüzgâra bırak. Bırakmak da büyütmenin bir parçası."},{"herb_id":"nane","names":{"tr":"Nane","en":"Peppermint","la":"Mentha piperita"},"gezegen_birincil":"merkur","gezegen_ikincil":["mars"],"celiski_notu":"⚠ KIRILGAN: ham frekans Mars'ta yüksek (20) ama kaynaklar naneyi sinir-sistemi/solunum için açıkça Merkür grubuna yazıyor ('İletişim, sinir sistemi, akciğer: Nane, lavanta, rezene'). Keskin tat Mars niteliği → ikincil. Botanik terapötik kimlik (nöral/solunum = Merküryen sistemler) → birincil Merkür. Alternatif okuma Mars; Türkan vetosu için işaretli.","beden_bolgeleri":["sinir-uyku","gogus-nefes","mide-sindirim"],"tat":["keskin","serinletici-aromatik"],"enerjetik":{"isi":"serinletici (mentol paradoksu)","nem":"provisional","durum":"kaynakta serinletici bağlam"},"mevsim":["yaz"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"doğrulanmadı","not":"T-listesinde yok."},"kaynak_sayisi":16,"source_note":"Mars 20 / Merkür 12; atama kimlik yorumuyla Merkür.","mevsim_tipi":"botanik","tek_satir":"Merkür'ün taze soluğu; zihni durultan yaprak.","story_narrative":"Nane, geleneksel metinlerde Merkür'ün bitkileri arasında anılır — zihnin ve tazeliğin gezegenine yakışır biçimde. Bir yaprağına dokunmak bile havayı değiştirir.\n\nEski bahçelerde bulanıklığa karşı berraklığın bitkisi sayılmıştır. Keskin tarafı ise ona Mars'tan küçük bir kıvılcım katar.","ritual":"Zihnin kalabalıklaştığında bir nane yaprağını parmaklarında ov ve kokla — yoksa, o ferahlığı hatırla. Sonra tek cümle yaz: 'Şu an asıl önemli olan…' Berraklık, çoğu zaman tek cümledir."},{"herb_id":"biberiye","names":{"tr":"Biberiye","en":"Rosemary","la":"Rosmarinus officinalis"},"gezegen_birincil":"gunes","gezegen_ikincil":["saturn","mars"],"celiski_notu":null,"beden_bolgeleri":["kalp-dolasim","sinir-uyku"],"tat":["keskin","aromatik-buruk"],"enerjetik":{"isi":"ısıtıcı","nem":"kurutucu","durum":"provisional; kaynak bağlamı ısıtıcı"},"mevsim":["her-mevsim"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"doğrulanmadı","not":"T-listesinde yok."},"kaynak_sayisi":15,"source_note":"Güneş (vitalite/kalp/hafıza) baskın (19).","mevsim_tipi":"botanik","tek_satir":"Güneş'in hatırlayan dalı; canlılığı çağıran koku.","story_narrative":"Biberiye, geleneksel gelenekte Güneş'in bitkileri arasında sayılır — Akdeniz yamaçlarında ışığı biriktiren, kışın bile yeşil kalan bir dal. Kokusu eski metinlerde hatırlamayla ve canlılıkla birlikte anılır.\n\nSadakatin ve anmanın bitkisi olarak da geçer; kapı önlerine, defter aralarına konmuş, unutmamak isteyenlere eşlik etmiştir.","ritual":"Bir biberiye dalına dokun ya da kokusunu zihninde canlandır. Kendine sor: 'Bugün neyi hatırlamak istiyorum?' Cevabını tek satırla not et — güneş ışığı gibi kısa ve net."},{"herb_id":"isirgan","names":{"tr":"Isırgan","en":"Nettle","la":"Urtica dioica"},"gezegen_birincil":"mars","gezegen_ikincil":["saturn"],"celiski_notu":null,"beden_bolgeleri":["kalp-dolasim","kas-eklem"],"tat":["buruk","mineralli"],"enerjetik":{"isi":"provisional","nem":"kurutucu","durum":"dogrulanamadi"},"mevsim":["ilkbahar"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"doğrulanmadı","not":"T-listesinde yok."},"kaynak_sayisi":15,"source_note":"Mars (demir/kan/uyarıcı/dikenli) kimlik — ilişkisel değil, öz nitelik.","mevsim_tipi":"botanik","tek_satir":"Mars'ın koruyucu yeşili; sınır çizmeyi bilen bitki.","story_narrative":"Isırgan, geleneksel metinlerde Mars'ın güçlü bitkileri arasında anılır. Dokunana mesafesini hissettirir; ama onu tanıyanlar için baharın en cömert yeşillerinden biri sayılmıştır.\n\nEski kültürde gücün ve dayanıklılığın bahsiyle geçer — demir gibi sağlam, dikeni kadar cömert. Korumak ile cömertlik, onda aynı gövdede durur.","ritual":"Isırganı uzaktan hayal et: dokunulmaya izin vermeyen ama çevresine cömert bir bitki. İçinden geçir: 'Sınır koymak, sevgisizlik değildir.' Bugün nazikçe koruyacağın bir sınırını seç."},{"herb_id":"melisa","names":{"tr":"Melisa (Oğulotu)","en":"Lemon Balm","la":"Melissa officinalis"},"gezegen_birincil":"merkur","gezegen_ikincil":["ay"],"celiski_notu":"Merkür (17) baskın ama Ay eşleşmesi güçlü (duygu/su grubu). Merkür = sinir/zihinsel akış kimliği birincil; Ay = duygusal yatıştırma güçlü ikincil. Sınır bitkisi; Türkan isterse Ay'a çevirebilir.","beden_bolgeleri":["sinir-uyku","mide-sindirim"],"tat":["tatlımsı","aromatik"],"enerjetik":{"isi":"provisional","nem":"provisional","durum":"dogrulanamadi"},"mevsim":["yaz"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"doğrulanmadı","not":"T-listesinde yok."},"kaynak_sayisi":14,"source_note":"Merkür (sinir) + Ay (duygu/su) çift güçlü; kimlik yorumu Merkür.","mevsim_tipi":"botanik","tek_satir":"Merkür'ün limon kokulu sükûneti; düşüncelere yumuşak dokunan yaprak.","story_narrative":"Melisa, geleneksel metinlerde Merkür'ün sakin yüzünü taşıyan bitkiler arasında anılır; limonu andıran kokusuyla zihne dokunur. Ay'ın duygusal sularına da yakın durur — sınırda yaşayan bir bitkidir.\n\nEski bahçe kültüründe arıların sevgilisi olarak geçer; adını da oradan alır. Akşamların ve yumuşayan düşüncelerin bitkisi sayılmıştır.","ritual":"Akşam, melisa yaprağının kokusunu hayal et ve zihninde dönen cümlelerden birini kâğıda bırak. Yazılan düşünce, taşınan düşünceden hafiftir."},{"herb_id":"lavanta","names":{"tr":"Lavanta","en":"Lavender","la":"Lavandula angustifolia"},"gezegen_birincil":"merkur","gezegen_ikincil":["saturn"],"celiski_notu":null,"beden_bolgeleri":["sinir-uyku","gogus-nefes"],"tat":["aromatik-buruk"],"enerjetik":{"isi":"provisional","nem":"provisional","durum":"dogrulanamadi"},"mevsim":["yaz"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"doğrulanmadı","not":"T-listesinde yok."},"kaynak_sayisi":13,"source_note":"Merkür (sinir/solunum) baskın (23).","mevsim_tipi":"botanik","tek_satir":"Merkür'ün akşam moru; günü yumuşakça kapatan koku.","story_narrative":"Lavanta, geleneksel metinlerde Merkür'ün bitkileri arasında sayılır — akşamın ve sükûnetin tarafında duran bir bitki olarak. Mor tarlaları, telaşlı bir günün sonunda gözün dinlendiği yer gibidir.\n\nEski kültürde temizliğin, sandıkların ve akşamların kokusu olmuş; huzuru gösterişsizce çağırmıştır.","ritual":"Gün biterken lavanta kokusunu üç yavaş nefesle içine çek — gerçek ya da hayalî. Her nefeste günün bir parçasını yarına devretmeden bırak. Gece, bırakılan yerden başlar."},{"herb_id":"adacayi","names":{"tr":"Adaçayı","en":"Sage","la":"Salvia officinalis"},"gezegen_birincil":"jupiter","gezegen_ikincil":["merkur","gunes"],"celiski_notu":"⚠ EN KIRILGAN ATAMA: kaynaklar üçe bölünmüş (Jüpiter karaciğer-kan / Merkür solunum-sinir / Güneş kalp). Jüpiter'e 'karaciğer-kan temizleyici, fazlalık giderici' bağlamıyla hafif üstünlük verildi ama zayıf. Türkan önceliğle karar vermeli.","beden_bolgeleri":["gogus-nefes","karaciger"],"tat":["acı","aromatik-buruk"],"enerjetik":{"isi":"ısıtıcı","nem":"kurutucu","durum":"provisional"},"mevsim":["yaz","kis"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":"T3_CAUTION","uyari_chip":"Tujon/kamfor içerir; gebelikte kontrendike (EMA). Mutfak miktarı ayrı değerlendirilir.","gebelik":"yasak (contraindications.json)","not":"contraindications.json 'sage' T3 kaydıyla eşleşti. Etkileşim: antikonvülzan, sedatif, antidiyabetik. Kart detay yüzünde uyarı çipi ZORUNLU."},"kaynak_sayisi":13,"source_note":"Dağınık; Jüpiter geçici birincil.","mevsim_tipi":"botanik","tek_satir":"Jüpiter'in bilge yaprağı; olgunluğun ve ölçülü gücün bitkisi.","story_narrative":"Adaçayı, geleneksel metinlerde bilgelikle birlikte anılır; Jüpiter'in genişleten, olgunlaştıran doğasına yakıştırılmıştır. Gümüş yeşili yaprakları ona ağırbaşlı bir ışıltı verir.\n\nEski kültürlerde berraklığın ve olgunluğun imgesi olmuştur. Güçlü bir bitkidir — gücü, ona saygıyla yaklaşmayı öğretir.","ritual":"Adaçayının gümüş yeşilini gözünde canlandır ve kendine sor: 'Bugün neyi bilgece bırakıyorum?' Bırakmak da bir olgunluk biçimidir. (Bu bitkinin detayında güvenlik notu vardır; ona göz atmayı ihmal etme.)"},{"herb_id":"atkuyrugu","names":{"tr":"Atkuyruğu (Kırkkilit)","en":"Horsetail","la":"Equisetum arvense"},"gezegen_birincil":"saturn","gezegen_ikincil":[],"celiski_notu":null,"beden_bolgeleri":["kas-eklem","bobrek-mesane"],"tat":["mineralli","buruk"],"enerjetik":{"isi":"provisional","nem":"kurutucu","durum":"dogrulanamadi"},"mevsim":["ilkbahar"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"doğrulanmadı","not":"T-listesinde yok; Satürn rafının pilotta tek güçlü temsili."},"kaynak_sayisi":9,"source_note":"Satürn (kemik/mineral/silika/yapı) baskın (13) — saturnien kimlik net.","mevsim_tipi":"botanik","tek_satir":"Satürn'ün kadim iskeleti; sabrın ve yapının bitkisi.","story_narrative":"Atkuyruğu, geleneksel metinlerde Satürn'ün bitkileri arasında sayılır — yapının ve sabrın gezegenine ait. Milyonlarca yıldır biçimini korumuş, dinozorlardan eski bir bitkidir.\n\nEski kültürde sağlamlığın ve süreklilik bilgeliğinin imgesi olmuş; süsü değil, duruşu temsil etmiştir.","ritual":"Otururken ya da yürürken bir an omurganı fark et; atkuyruğunun dimdik sapları gibi, zorlamadan doğrul. İçinden geçir: 'Yavaş büyüyen, sağlam durur.'"},{"herb_id":"sari_kantaron","names":{"tr":"Sarı Kantaron","en":"St John's Wort","la":"Hypericum perforatum"},"gezegen_birincil":"gunes","gezegen_ikincil":["saturn"],"celiski_notu":null,"beden_bolgeleri":["sinir-uyku","deri"],"tat":["buruk","acımsı"],"enerjetik":{"isi":"provisional","nem":"provisional","durum":"dogrulanamadi"},"mevsim":["yaz"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":"gundonumu","guvenlik":{"app_safe":true,"guven_tier":"T2_INTERACTION","uyari_chip":"Güçlü ilaç etkileşimi: doğum kontrol hapının etkisini düşürür; SSRI ile ciddi risk. İlaç kullanıyorsan bir uzmana danış.","gebelik":"yasak (contraindications.json)","not":"contraindications.json 'st_johns_wort' T2 kaydıyla eşleşti. Etkileşim listesi: doğum kontrol, SSRI, warfarin, siklosporin, digoksin, HIV antiretroviral, triptan. Kart detay yüzünde uyarı çipi ZORUNLU. Motor kuralı: ilaç kullanana önerme."},"kaynak_sayisi":9,"source_note":"Güneş (ışık/'güneş otu') baskın (13). Gündönümü çiçeklenmesi → ilk kozmik_olay kart adayı.","mevsim_tipi":"botanik","tek_satir":"Güneş'i depolayan çiçek; yılın en uzun gününde açan ışık.","story_narrative":"Sarı kantaron, geleneksel metinlerde Güneş'in bitkileri arasında anılır; sarı çiçekleri yaz gündönümü civarında, ışığın en cömert günlerinde açar. Eski kültürlerde bu yüzden gündönümü kutlamalarının bitkisi olmuştur.\n\nKaranlığa karşı ışığı hatırlatan bir imge olarak geçer; adı ve hikâyesi, yılın dönüm noktasına bağlıdır. Güçlü bir bitkidir — detayındaki güvenlik notu, ona duyulan saygının parçasıdır.","ritual":"Gün içinde güneş gören bir köşede bir dakika dur. Işığın tenindeki sıcaklığını fark et ve içinden geçir: 'Işık biriktirilebilir.' Bu kart, yılda bir kez, gündönümünde açar — onu bulduğun günü hatırla."},{"herb_id":"aynisefa","names":{"tr":"Aynısefa","en":"Calendula","la":"Calendula officinalis"},"gezegen_birincil":"gunes","gezegen_ikincil":["mars"],"celiski_notu":null,"beden_bolgeleri":["deri"],"tat":["acımsı"],"enerjetik":{"isi":"ısıtıcı","nem":"kurutucu","durum":"provisional"},"mevsim":["yaz","sonbahar"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"doğrulanmadı","not":"T-listesinde yok."},"kaynak_sayisi":16,"source_note":"Güneş çok net (17); klasik calendula=Güneş kimliğiyle birebir.","mevsim_tipi":"botanik","tek_satir":"Güneş'i izleyen çiçek; günün ışığını yüzeyine taşır.","story_narrative":"Aynısefa, geleneksel metinlerde Güneş'in bitkileri arasında anılır — turuncu taç yaprakları sabah ışıkla açılır, gün boyunca güneşi izler. Bahçelerin en cömert çiçeklerindendir; uzun mevsim boyunca açmayı sürdürür.\n\nEski bitki kültüründe koruyan, saran ve aydınlatan bir imge olarak yazılmış; cömertliğin turuncu yüzü sayılmıştır.","ritual":"Sabah güne başlarken yüzünü bir dakika ışığa çevir. Aynısefanın güneşi izleyişini hatırla ve kendine sor: bugün neye yönelmek istiyorum?"},{"herb_id":"kekik","names":{"tr":"Kekik","en":"Thyme","la":"Thymus vulgaris"},"gezegen_birincil":"merkur","gezegen_ikincil":["venus","jupiter"],"celiski_notu":"⚠ EN KIRILGAN: klasik Culpeper geleneği kekiği Venüs'e yazar; taramamızda Venüs sinyali hiç çıkmadı (Merkür 5 / Jüpiter 4 / Ay 4). Solunum-uyarıcı kimlikle Merkür verildi — VETO öncelikli.","beden_bolgeleri":["gogus-nefes"],"tat":["keskin"],"enerjetik":{"isi":"ısıtıcı","nem":"kurutucu","durum":"provisional"},"mevsim":["yaz","kis"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"doğrulanmadı","not":"T-listesinde yok."},"kaynak_sayisi":9,"source_note":"Sinyal dağınık; kimlik yorumu Merkür.","mevsim_tipi":"botanik","tek_satir":"Dağın keskin kokusu; zihni tazeleyen küçük yaprak.","story_narrative":"Kekik, kaynaklarda canlılığın bitkileri arasında, Merkür'ün grubunda anılır. Küçük yaprakları güneşte yoğun bir koku biriktirir; dağ yamaçlarının dayanıklı sakinidir.\n\nEski kültürde cesaretle de ilişkilendirilmiş; zihnin dağınıklığına karşı keskin ve toparlayıcı bir imge olarak geçer.","ritual":"Bir tutam kekiği parmaklarında ov ya da kokusunu zihninde canlandır. Ardından günün tek önceliğini bir cümleyle söyle — keskin koku gibi net."},{"herb_id":"hatmi","names":{"tr":"Hatmi","en":"Marshmallow","la":"Althaea officinalis"},"gezegen_birincil":"venus","gezegen_ikincil":["ay"],"celiski_notu":null,"beden_bolgeleri":["gogus-nefes","mide-sindirim"],"tat":["tatlımsı"],"enerjetik":{"isi":"serinletici","nem":"nemlendirici","durum":"provisional; klasik mukilaj kimliği"},"mevsim":["yaz"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"doğrulanmadı","not":"T-listesinde yok."},"kaynak_sayisi":9,"source_note":"Venüs 9 net (klasik mallow=Venüs); Ay güçlü ikincil (nemlendirici).","mevsim_tipi":"botanik","tek_satir":"Venüs'ün yumuşak eli; sertliği yumuşaklıkla saran çiçek.","story_narrative":"Hatmi, geleneksel metinlerde Venüs'ün yumuşak bitkileri arasında sayılır; Ay'ın nemli doğasına da yakın durur. Eski kültürde 'saran' imgesiyle, yumuşaklığın tarafında anılmıştır.\n\nSertleşen, kuruyan ve gerilen ne varsa onun karşısına yumuşaklıkla çıkan bir bitki olarak yazılmıştır — şefkatin botanik hali.","ritual":"Bugün içinde sertleşmiş bir düşünce varsa, onu hatminin yumuşaklığıyla sarmayı hayal et. Sertliği çözmek gerekmez; şimdilik sarmak yeter."},{"herb_id":"civanpercemi","names":{"tr":"Civanperçemi","en":"Yarrow","la":"Achillea millefolium"},"gezegen_birincil":"venus","gezegen_ikincil":["mars"],"celiski_notu":null,"beden_bolgeleri":["kalp-dolasim","deri"],"tat":["buruk","acı"],"enerjetik":{"isi":"provisional","nem":"kurutucu","durum":"provisional"},"mevsim":["yaz"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"doğrulanmadı","not":"T-listesinde yok; bazı literatürde gebelik uyarısı anılır, vault'ta kayıt YOK — eklenmesi Türkan kararı."},"kaynak_sayisi":8,"source_note":"Venüs önde (4), klasik yarrow=Venüs; Mars savaşçı-yara bağlamı ikincil.","mevsim_tipi":"botanik","tek_satir":"Savaşçıların nazik yoldaşı; gücü ve inceliği aynı sapta taşır.","story_narrative":"Civanperçemi, adını eski hikâyelerde savaşçılara eşlik etmesinden alır; Latince adı Akhilleus'a uzanır. Kaynaklarda Venüs'ün grubunda anılır — sertliğin ortasında incelikle duran bir bitki.\n\nİnce dilimli yaprakları ve beyaz şemsiye çiçekleriyle, dayanıklılığın zarafetle birleşebileceğini hatırlatan bir imge olmuştur.","ritual":"Bugün hem güçlü hem nazik olman gereken bir anı düşün. Civanperçemini hatırla: ikisi aynı anda mümkün."},{"herb_id":"sarimsak","names":{"tr":"Sarımsak","en":"Garlic","la":"Allium sativum"},"gezegen_birincil":"mars","gezegen_ikincil":["saturn"],"celiski_notu":null,"beden_bolgeleri":["kalp-dolasim","mide-sindirim"],"tat":["keskin"],"enerjetik":{"isi":"ısıtıcı","nem":"kurutucu","durum":"provisional"},"mevsim":["yaz"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"doğrulanmadı","not":"T-listesinde yok; bilinen antikoagülan etkileşimi vault'ta YOK — Türkan kararı (zencefil notuyla aynı durum)."},"kaynak_sayisi":8,"source_note":"Mars 9, net.","mevsim_tipi":"botanik","tek_satir":"Mars'ın keskin kalkanı; koruyuculuğu kokusundan belli.","story_narrative":"Sarımsak, geleneksel kültürde Mars'ın güçlü ve koruyucu bitkileri arasında anılır. Keskin kokusu, eski inanışlarda kapılara asılan bir koruma işareti olmuş; gücünü saklamayan bir bitkidir.\n\nKaynaklarda canlılık ve direnç bahsiyle geçer — küçük bir dişin içinde beklenmedik bir kuvvet.","ritual":"Bugün korumak istediğin bir şeyi adlandır: vaktin, enerjin ya da bir sınırın. Sarımsağın açık sözlü koruyuculuğunu örnek al — nazikçe ama net."},{"herb_id":"menekse","names":{"tr":"Menekşe","en":"Violet","la":"Viola odorata"},"gezegen_birincil":"venus","gezegen_ikincil":["saturn"],"celiski_notu":null,"beden_bolgeleri":["gogus-nefes","deri"],"tat":["tatlımsı"],"enerjetik":{"isi":"serinletici","nem":"nemlendirici","durum":"provisional"},"mevsim":["ilkbahar"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"doğrulanmadı","not":"T-listesinde yok."},"kaynak_sayisi":7,"source_note":"Venüs 6, klasik violet=Venüs ile uyumlu.","mevsim_tipi":"botanik","tek_satir":"Gölgede açan tevazu; Venüs'ün en sessiz armağanı.","story_narrative":"Menekşe, geleneksel metinlerde Venüs'ün narin bitkileri arasında sayılır. Erken baharda, çoğu çiçekten önce ve genellikle gölgede açar — görünmek için değil, var olmak için açan bir çiçektir.\n\nEski kültürde tatlılığın ve alçakgönüllülüğün imgesi olmuş; sessiz bir zarafetle anılmıştır.","ritual":"Bugün gösterişsiz ama sana iyi gelen tek bir şey yap — kimse görmese de. Menekşe gibi: sessiz, ama gerçek."},{"herb_id":"ihlamur","names":{"tr":"Ihlamur","en":"Linden","la":"Tilia cordata"},"gezegen_birincil":"ay","gezegen_ikincil":["jupiter","venus"],"celiski_notu":"Bazı geleneklerde Jüpiter/Venüs'e yazılır; kaynak sinyalimiz Ay önde (6) ve yatıştırıcı-uyku kimliği Ay'la uyumlu → birincil Ay. Ay rafını güçlendiren atama; veto açık.","beden_bolgeleri":["sinir-uyku","gogus-nefes"],"tat":["tatlımsı"],"enerjetik":{"isi":"provisional","nem":"nemlendirici","durum":"provisional"},"mevsim":["yaz"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"doğrulanmadı","not":"T-listesinde yok."},"kaynak_sayisi":6,"source_note":"Ay 6 / Satürn 3 / Merkür 2.","mevsim_tipi":"botanik","tek_satir":"Ay'ın sıcak fısıltısı; koca bir ağacın en yumuşak armağanı.","story_narrative":"Ihlamur, kaynaklarda Ay'ın yumuşak bitkileri arasında öne çıkar — akşamın, dinginliğin ve iç sıcaklığın imgesi. Kocaman bir ağacın minicik, bal kokulu çiçekler vermesi onun karakterini anlatır.\n\nEski kültürde köy meydanlarının gölge ağacı olmuş; altında toplanılan, dinlenilen bir varlık olarak hikâyelere girmiştir.","ritual":"Akşam, bir ıhlamur ağacının altında oturduğunu hayal et. Üç yavaş nefes al ve günün gürültüsünü yapraklara bırak."},{"herb_id":"maydanoz","names":{"tr":"Maydanoz","en":"Parsley","la":"Petroselinum crispum"},"gezegen_birincil":"merkur","gezegen_ikincil":["venus"],"celiski_notu":"⚠ KIRILGAN: sinyal zayıf ve Venüs önde çıktı (3'e 1); klasik gelenek maydanozu Merkür'e yazar — kimlik kararıyla Merkür verildi, veto açık.","beden_bolgeleri":["bobrek-mesane","mide-sindirim"],"tat":["keskin","yeşil-acımsı"],"enerjetik":{"isi":"ısıtıcı","nem":"kurutucu","durum":"provisional"},"mevsim":["ilkbahar","sonbahar"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"doğrulanmadı","not":"T-listesinde yok; yüksek miktarda gebelik uyarısı literatürde bilinir, vault'ta kayıt YOK — eklenmesi Türkan kararı."},"kaynak_sayisi":6,"source_note":"Düşük sinyal; kimlik yorumu.","mevsim_tipi":"botanik","tek_satir":"Mutfağın yeşil habercisi; tazeliği güne taşıyan yaprak.","story_narrative":"Maydanoz, geleneksel gelenekte Merkür'ün canlı ve hafif bitkileri arasında anılır. Her sofraya sızan tazeliğiyle, sıradan günlere küçük bir yeşil dokunuş getirir.\n\nEski metinlerde tazelik ve ferahlık bahsiyle geçer; ağırlığı değil hafifliği temsil eden bir yeşilliktir.","ritual":"Bugün gününe küçük bir tazelik ekle: pencereyi aç, masanı topla ya da kısa bir yürüyüşe çık. Maydanoz kadar basit, o kadar etkili."},{"herb_id":"anason","names":{"tr":"Anason","en":"Anise","la":"Pimpinella anisum"},"gezegen_birincil":"merkur","gezegen_ikincil":["ay"],"celiski_notu":null,"beden_bolgeleri":["mide-sindirim","gogus-nefes"],"tat":["tatlımsı","keskin"],"enerjetik":{"isi":"ısıtıcı","nem":"kurutucu","durum":"provisional"},"mevsim":["sonbahar"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"doğrulanmadı","not":"T-listesinde yok."},"kaynak_sayisi":5,"source_note":"Merkür 8, net-ish; rezeneyle aynı aile-kimlik.","mevsim_tipi":"botanik","tek_satir":"Tatlı kokulu tohum; söze yumuşaklık katan koku.","story_narrative":"Anason, kaynaklarda Merkür'ün bitkileri arasında anılır. Minik tohumları yoğun, tatlı bir koku taşır — küçük şeylerin güçlü olabileceğinin kanıtı gibi.\n\nEski kültürlerde tatlılığın ve yumuşaklığın imgesiyle geçer; şemsiye biçimli çiçekleri yaz göğüne açılır.","ritual":"Konuşmadan önce bir nefes: anasonun tatlılığını hatırla ve söyleyeceğin cümleyi bir tık yumuşat. Anlam aynı kalır, etki değişir."},{"herb_id":"gul","names":{"tr":"Gül","en":"Rose","la":"Rosa damascena"},"gezegen_birincil":"venus","gezegen_ikincil":["ay"],"celiski_notu":"Dar arama kalıbı kullanıldı (kelime gürültüsü nedeniyle) → frekans temkinli okunmalı. Kimlik tartışmasız Venüs (evrensel klasik); onay için işaretli.","beden_bolgeleri":["kalp-dolasim","deri"],"tat":["buruk","tatlımsı"],"enerjetik":{"isi":"serinletici","nem":"provisional","durum":"provisional"},"mevsim":["ilkbahar","yaz"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"doğrulanmadı","not":"T-listesinde yok."},"kaynak_sayisi":3,"source_note":"Dar pattern 3 kaynak; Venüs=Mars=3 eşit, kimlik Venüs.","mevsim_tipi":"botanik","tek_satir":"Venüs'ün kalbi; dikeniyle de taçlarıyla da sevmenin çiçeği.","story_narrative":"Gül, geleneksel metinlerde Venüs'ün baş tacıdır — kalbin, güzelliğin ve inceliğin çiçeği. Kokusu yüzyıllardır ferahlığın ve zarafetin simgesi olmuş; bahçelerin kraliçesi sayılmıştır.\n\nDikeniyle birlikte anılması boşuna değildir: sevginin sınırla, güzelliğin korunmayla yan yana durabileceğini hatırlatır.","ritual":"Bugün kalbine iyi gelen bir şeye bilerek zaman ayır — bir koku, bir ses, bir insan. Gül gibi: hem açık hem sınırlı olmak mümkün."},{"herb_id":"devedikeni","names":{"tr":"Devedikeni","en":"Milk Thistle","la":"Silybum marianum"},"gezegen_birincil":"jupiter","gezegen_ikincil":["mars"],"celiski_notu":null,"beden_bolgeleri":["karaciger"],"tat":["acı"],"enerjetik":{"isi":"provisional","nem":"provisional","durum":"dogrulanamadi"},"mevsim":["yaz"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"doğrulanmadı","not":"T-listesinde yok."},"kaynak_sayisi":11,"source_note":"Jüpiter 10 — net; klasik karaciğer kimliğiyle birebir.","mevsim_tipi":"botanik","tek_satir":"Jüpiter'in dikenli bekçisi; gücünü korumasıyla gösterir.","story_narrative":"Devedikeni, kaynaklarda Jüpiter'in bitkileri arasında anılır. Mor çiçeğini dikenli bir zırhın ortasında taşır — değerli olanın korunmaya değer olduğunu bilir gibi.\n\nEski kültürde dayanıklılığın ve yenilenmenin imgesi olmuş; sütlü damarlı yaprakları ona adını ve hikâyesini vermiştir.","ritual":"Bugün kendi enerjini koruduğun bir sınırı fark et. Devedikeni gibi: merkezde yumuşaklık, çeperde netlik."},{"herb_id":"kediotu","names":{"tr":"Kediotu","en":"Valerian","la":"Valeriana officinalis"},"gezegen_birincil":"merkur","gezegen_ikincil":["mars"],"celiski_notu":null,"beden_bolgeleri":["sinir-uyku"],"tat":["acımsı","topraksı"],"enerjetik":{"isi":"ısıtıcı","nem":"provisional","durum":"provisional"},"mevsim":["sonbahar"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"doğrulanmadı","not":"T-listesinde yok. Sedatiflerle etkileşim literatürde bilinir; vault'ta kayıt YOK — eklenmesi Türkan kararı."},"kaynak_sayisi":8,"source_note":"Merkür 11 — ezici; klasik valerian=Merkür ile uyumlu. Merkür-freni hedefine rağmen sinyal+kimlik gereği dürüst atama.","mevsim_tipi":"botanik","tek_satir":"Toprağın altında saklı sükûnet; geceye eşlik eden kök.","story_narrative":"Kediotu, kaynaklarda Merkür'ün grubunda anılır — zihin bitkilerinin en sakin yüzü. Gücü çiçeğinde değil, toprağın altındaki kökündedir.\n\nEski kültürde gece ve dinginlikle ilişkilendirilmiş; kedilerin ona duyduğu ilgi, adına ve hikâyelerine karışmıştır.","ritual":"Yatmadan önce zihninden geçen son üç düşünceyi bir kâğıda bırak. Kök gibi: karanlıkta bekleyebilirler, sen dinlen."},{"herb_id":"hindiba","names":{"tr":"Hindiba","en":"Chicory","la":"Cichorium intybus"},"gezegen_birincil":"jupiter","gezegen_ikincil":["merkur"],"celiski_notu":"Merkür 6 = Jüpiter 6 tam eşitlik. Klasik gelenek (succory=Jüpiter) + karaciğer-acı tonik kimliği → birincil Jüpiter. Veto açık.","beden_bolgeleri":["karaciger","mide-sindirim"],"tat":["acı"],"enerjetik":{"isi":"serinletici","nem":"kurutucu","durum":"provisional"},"mevsim":["yaz","sonbahar"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"doğrulanmadı","not":"T-listesinde yok."},"kaynak_sayisi":6,"source_note":"Eşitlik → P2 kimlik kuralı uygulandı.","mevsim_tipi":"botanik","tek_satir":"Yol kenarının mavi bilgesi; kendi ritmini bilen çiçek.","story_narrative":"Hindiba, kaynaklarda Jüpiter'in bitkileri arasında geçer. Gök mavisi çiçekleri sabah açılır, öğleden sonra kapanır — kendi ritmini bilen bir bitkidir.\n\nEski kültürde yol kenarında serpilen dayanıklılığın imgesi olmuştur; gösterişsiz yerlerde bile kendi maviliğini açar.","ritual":"Bugün sana 'acı' gelen bir gerçeği yumuşakça kabul et. Hindiba gibi: yol kenarında bile kendi maviliğini açmak mümkün."},{"herb_id":"tarcin","names":{"tr":"Tarçın","en":"Cinnamon","la":"Cinnamomum verum"},"gezegen_birincil":"gunes","gezegen_ikincil":["mars","saturn"],"celiski_notu":"⚠ KIRILGAN: sinyal dağınık ve Satürn önde (3/2/2). Satürn bağlamı 'soğuğa karşı ısıtıcı' ilişkisel kullanım (zencefil emsali). Sıcak-aromatik kimlik + klasik gelenek → Güneş. Veto öncelikli.","beden_bolgeleri":["mide-sindirim","kalp-dolasim"],"tat":["keskin","tatlımsı"],"enerjetik":{"isi":"ısıtıcı","nem":"kurutucu","durum":"provisional"},"mevsim":["her-mevsim"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"doğrulanmadı","not":"T-listesinde yok. Cassia türünde kumarin notu literatürde bilinir; vault'ta kayıt YOK — Türkan kararı."},"kaynak_sayisi":5,"source_note":"Kimlik yorumu Güneş; frekans temkinli.","mevsim_tipi":"geleneksel-sembolik","tek_satir":"Güneş'in kabuğa sarılmış sıcaklığı; içini ısıtan baharat.","story_narrative":"Tarçın, geleneksel kültürde Güneş'in sıcak bitkileri arasında anılır. Bir ağaç kabuğunun bu kadar koku ve ısı taşıması, eski metinlerde güneş ışığının depolanması gibi anlatılmıştır.\n\nSoğuk mevsimlerin ve soğuyan hallerin karşısına konan bir imge olmuş; şenlik, sofra ve sıcaklıkla birlikte hatırlanır.","ritual":"Üşüdüğünü hissettiğin bir anda — bedenen ya da içsel — sıcak bir şeyi iki eline al ve üç nefes boyunca yalnız ısıyı fark et."},{"herb_id":"marul","names":{"tr":"Marul","en":"Lettuce","la":"Lactuca sativa"},"gezegen_birincil":"ay","gezegen_ikincil":[],"celiski_notu":"Sinyal düşük (Ay 2) ama tek yönlü; klasik gelenek (lettuce=Ay) ezici. Kimlik ataması — veto hafif.","beden_bolgeleri":["sinir-uyku","mide-sindirim"],"tat":["sulu","acımsı"],"enerjetik":{"isi":"serinletici","nem":"nemlendirici","durum":"provisional"},"mevsim":["ilkbahar"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"doğrulanmadı","not":"T-listesinde yok."},"kaynak_sayisi":5,"source_note":"Ay rafını 2→3 yapan atama.","mevsim_tipi":"botanik","tek_satir":"Ay'ın sulu yaprağı; akşamın serinliğini taşıyan yeşil.","story_narrative":"Marul, klasik gelenekte Ay'ın bitkileri arasında sayılır — sulu, serin ve dingin. Gündüzün hızına değil, akşamın yavaşlığına aittir.\n\nEski metinlerde dinginlik ve akşam bahsiyle birlikte geçer; en gösterişsiz yeşilliklerin bile bir gökyüzü hikâyesi olabileceğini hatırlatır.","ritual":"Bir akşam yemeğini telefonsuz ve yavaş ye. Ay'ın bitkisi gibi: serin, sakin, acelesiz."},{"herb_id":"ceviz","names":{"tr":"Ceviz","en":"Walnut","la":"Juglans regia"},"gezegen_birincil":"saturn","gezegen_ikincil":["gunes"],"celiski_notu":"⚠ KIRILGAN: klasik gelenekte Güneş/Jüpiter atamaları da var; kaynak sinyalimiz Satürn önde (4/1) ve imza okuması (sert kabuk, dayanıklı ağaç, kıvrımlı iç) Satürn'ü destekliyor. Veto öncelikli.","beden_bolgeleri":["sinir-uyku"],"tat":["yağlı","buruk"],"enerjetik":{"isi":"ısıtıcı","nem":"kurutucu","durum":"provisional"},"mevsim":["sonbahar"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"doğrulanmadı","not":"T-listesinde yok."},"kaynak_sayisi":5,"source_note":"Satürn rafını güçlendiren aday.","mevsim_tipi":"botanik","tek_satir":"Satürn'ün mühürlü sandığı; sabrın içinde olgunlaşan öz.","story_narrative":"Ceviz, kaynaklarımızda Satürn'ün bitkileri arasında anılır — sert kabuğu, dayanıklı ağacı ve zamanla olgunlaşan içiyle. Kıvrımlı çekirdeği, eski imza öğretisinde düşünceyle ilişkilendirilmiştir.\n\nBir ceviz ağacı acele etmez; gölgesini ve meyvesini yıllara yayar. Satürn'ün dersi de budur: değerli olan, zaman ister.","ritual":"Henüz meyve vermemiş uzun vadeli bir emeğini düşün. Ceviz ağacını hatırla: kök salmak da bir ilerlemedir."},{"herb_id":"murver","names":{"tr":"Mürver","en":"Elder","la":"Sambucus nigra"},"gezegen_birincil":"saturn","gezegen_ikincil":["jupiter","ay"],"celiski_notu":"Culpeper geleneği mürveri Venüs'e yazar; kaynak sinyalimiz net Satürn (6) ve halk geleneğindeki 'Satürn ağacı' kimliğiyle uyumlu. Veto açık.","beden_bolgeleri":["gogus-nefes","deri"],"tat":["tatlımsı","buruk"],"enerjetik":{"isi":"provisional","nem":"provisional","durum":"dogrulanamadi"},"mevsim":["ilkbahar","sonbahar"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"doğrulanmadı","not":"T-listesinde yok. Çiğ meyve uyarısı literatürde bilinir; vault'ta kayıt YOK — Türkan kararı."},"kaynak_sayisi":4,"source_note":"Folklor + sinyal örtüştü.","mevsim_tipi":"botanik","tek_satir":"Bahçenin yaşlı bekçisi; eşiklerin ve geçişlerin ağacı.","story_narrative":"Mürver, halk geleneğinde Satürn'ün ağacı olarak anılır — bahçelerin kıyısında, eşiklerde ve geçiş yerlerinde büyür. Baharda köpük gibi beyaz çiçekler, güzün koyu salkımlar verir; iki mevsimin de dilini konuşur.\n\nEski kültürde saygı duyulan, izinsiz kesilmeyen bir ağaç olmuş; koruyuculuk ve bilgelik hikâyeleriyle sarılmıştır.","ritual":"Bugün bir 'eşikte' olduğun alanı adlandır — biten ya da başlayan bir şey. Mürver gibi: eşikte durmak da bir yerdir."},{"herb_id":"serbetciotu","names":{"tr":"Şerbetçiotu","en":"Hops","la":"Humulus lupulus"},"gezegen_birincil":"venus","gezegen_ikincil":["saturn","mars"],"celiski_notu":"Klasik Culpeper hops=Mars der; kaynak sinyalimiz Venüs (4) ve yatıştırıcı-gevşetici kimlik Venüs okumasını destekliyor. Veto açık.","beden_bolgeleri":["sinir-uyku"],"tat":["acı"],"enerjetik":{"isi":"serinletici","nem":"provisional","durum":"provisional"},"mevsim":["sonbahar"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"doğrulanmadı","not":"T-listesinde yok."},"kaynak_sayisi":3,"source_note":"Düşük frekans; kimlik+sinyal uyumu.","mevsim_tipi":"botanik","tek_satir":"Venüs'ün sarılgan dinginliği; günü yumuşakça kapatan bitki.","story_narrative":"Şerbetçiotu, kaynaklarımızda Venüs'ün yumuşak grubunda anılır — akşamın ve günü kapatmanın bitkilerinden. Sarılgan gövdesiyle tutunacak bir şey bulur ve yükselir — sertlikle değil, esneklikle.\n\nEski kültürde dinlenmenin ve yavaşlamanın imgesi olmuş; tutunarak yükselen zarif gövdesiyle hikâyelere karışmıştır.","ritual":"Gün biterken omuzlarını bilinçli olarak gevşet ve içinden 'bugün buraya kadar' de. Şerbetçiotu gibi: bırakmak da bir tutunma biçimi."},{"herb_id":"ebegumeci","names":{"tr":"Ebegümeci","en":"Common Mallow","la":"Malva sylvestris"},"gezegen_birincil":"venus","gezegen_ikincil":["ay"],"celiski_notu":"Sinyal pratikte yok (1/1/1); atama tamamen kimlikle yapıldı — hatmiyle aynı aile, klasik mallow=Venüs. Veto hafif.","beden_bolgeleri":["gogus-nefes","mide-sindirim"],"tat":["tatlımsı"],"enerjetik":{"isi":"serinletici","nem":"nemlendirici","durum":"provisional"},"mevsim":["yaz"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"doğrulanmadı","not":"T-listesinde yok."},"kaynak_sayisi":3,"source_note":"Kimlik ataması; hatmi emsali.","mevsim_tipi":"botanik","tek_satir":"Kapı önlerinin sessiz şefkati; yumuşaklığını dert etmeyen ot.","story_narrative":"Ebegümeci, hatminin yabani kız kardeşi gibidir — kaynaklarda Venüs'ün yumuşak ailesinde anılır. Kaldırım kenarlarında, kapı önlerinde, kimsenin ekmediği yerlerde biter ve yine de cömerttir.\n\nEski kültürde halkın bitkisi olmuş; gösterişsiz pembe çiçekleri, şefkatin her yerde bulunabileceğini söyler gibidir.","ritual":"Bugün gözüne çarpan 'sıradan' bir güzelliğin önünde bir saniye dur. Şefkat çoğu zaman ayaküstü büyür."},{"herb_id":"nilufer","names":{"tr":"Nilüfer","en":"Water Lily","la":"Nymphaea alba"},"gezegen_birincil":"ay","gezegen_ikincil":[],"celiski_notu":null,"kaynak_tipi":"vault-ici","terfi_durumu":null,"agent_derin_kullanim":true,"beden_bolgeleri":["sinir-uyku","ureme-dongu"],"tat":["tatlımsı","sulu"],"enerjetik":{"isi":"serinletici","nem":"nemlendirici","durum":"provisional"},"mevsim":["yaz"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"doğrulanmadı","not":"T-listesinde yok."},"kaynak_sayisi":3,"source_note":"Ay 3, tek yönlü; klasik su-Ay bitkisi kimliğiyle birebir. Ay rafını güçlendirir.","mevsim_tipi":"botanik","tek_satir":"Ay'ın su aynası; derinden yükselip yüzeyde açan çiçek.","story_narrative":"Nilüfer, klasik gelenekte Ay'ın bitkileri arasında sayılır — köklerini suyun dibindeki karanlığa salar, çiçeğini yüzeyin ışığına açar. İki dünyayı aynı sapta birleştirir.\n\nEski kültürlerde saflığın ve sükûnetin imgesi olmuş; durgun suların üzerinde açan bu çiçek, derinlikten güzelliğe uzanan sessiz bir yolculuğu anlatır.","ritual":"Bugün derinde hissettiğin bir şeyin yüzeye çıkmasına izin ver — bir cümle yaz, bir nefes bırak. Nilüfer gibi: dipten gelen de ışığa açılabilir."},{"herb_id":"sogut","names":{"tr":"Söğüt","en":"Willow","la":"Salix alba"},"gezegen_birincil":"ay","gezegen_ikincil":[],"celiski_notu":"Vault sinyali çok zayıf (1 kaynak); atama klasik gelenek (willow=Ay, su kıyısı ağacı) + tek kaynak uyumuyla. Zayıf-vault-içi.","kaynak_tipi":"vault-ici-zayif","terfi_durumu":null,"agent_derin_kullanim":false,"beden_bolgeleri":["kas-eklem","sinir-uyku"],"tat":["acı","buruk"],"enerjetik":{"isi":"serinletici","nem":"nemlendirici","durum":"provisional"},"mevsim":["ilkbahar"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"doğrulanmadı","not":"T-listesinde yok; salisilat duyarlılığı literatürde bilinir, vault'ta kayıt YOK — Türkan kararı."},"kaynak_sayisi":1,"source_note":"Ay rafını 4→5 yapan aday; sinyal zayıf, kimlik güçlü.","mevsim_tipi":"botanik","tek_satir":"Suya eğilen sabır; esneyerek dayanan ağaç.","story_narrative":"Söğüt, klasik gelenekte Ay'a ve suyun kıyısına ait bir ağaç olarak anılır. Dalları yere eğilir ama kırılmaz; rüzgârda direnmek yerine onunla birlikte salınır.\n\nEski kültürde yasın ve şefkatin ağacı olmuş; eğilebilmenin de bir güç olduğunu, akıp geçene direnmemenin bilgeliğini hatırlatır.","ritual":"Bugün direndiğin bir şeyi düşün. Söğüdün dallarını hayal et: eğilmek teslim olmak değil, kırılmamanın yoludur. Bir an için gevşemeyi dene."},{"herb_id":"feslegen","names":{"tr":"Fesleğen","en":"Basil","la":"Ocimum basilicum"},"gezegen_birincil":"mars","gezegen_ikincil":["merkur"],"celiski_notu":"Vault sinyali pratikte yok (1/1); klasik Culpeper basil=Mars kanonu + keskin-aromatik kimlik → Mars. Merkür ikincil (aromatik-zihinsel). Zayıf-vault-içi, veto açık.","kaynak_tipi":"vault-ici-zayif","terfi_durumu":null,"agent_derin_kullanim":false,"beden_bolgeleri":["sinir-uyku","mide-sindirim"],"tat":["keskin","aromatik"],"enerjetik":{"isi":"ısıtıcı","nem":"kurutucu","durum":"provisional"},"mevsim":["yaz"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"doğrulanmadı","not":"T-listesinde yok."},"kaynak_sayisi":3,"source_note":"Klasik Mars kanonu.","mevsim_tipi":"botanik","tek_satir":"Mars'ın yeşil kıvılcımı; kokusuyla güne neşe katan yaprak.","story_narrative":"Fesleğen, klasik bitki geleneğinde Mars'ın canlı bitkileri arasında anılır — keskin, sıcak ve uyandırıcı kokusuyla. Küçük yapraklarında beklenmedik bir yoğunluk taşır.\n\nEski kültürlerde hem koruma hem canlanma imgesiyle geçer; bazı geleneklerde eşiklere, pencerelere konan bir bereket ve neşe bitkisi olmuştur.","ritual":"Bir fesleğen yaprağını koklamayı hayal et — ya da mutfağındaysa kokla. O tazelikle güne küçük bir canlılık çağır: bugün neyi biraz daha isteyerek yapabilirim?"},{"herb_id":"sigirkuyrugu","names":{"tr":"Sığırkuyruğu","en":"Mullein","la":"Verbascum thapsus"},"gezegen_birincil":"saturn","gezegen_ikincil":[],"celiski_notu":"Klasik gelenek ataması (vault taramasında yok). Verbascum=Satürn geleneksel kanon; uzun dik saplı, gri-tüylü yapısı saturnien imzayla uyumlu.","kaynak_tipi":"klasik-gelenek-vault-disi","terfi_durumu":"bekliyor","agent_derin_kullanim":false,"beden_bolgeleri":["gogus-nefes"],"tat":["acımsı","yumuşak"],"enerjetik":{"isi":"serinletici","nem":"nemlendirici","durum":"klasik-gelenek"},"mevsim":["yaz"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"doğrulanmadı","not":"contraindications.json KAPSAMI DIŞI (vault-dışı bitki). Toksik alkaloid içermeyen, geleneksel güvenli bitki olarak seçildi; tüyleri mekanik tahriş yapabilir. Yayın öncesi bağımsız güvenlik doğrulaması önerilir (launch checklist)."},"kaynak_sayisi":0,"source_note":"Satürn rafını güçlendiren vault-dışı klasik. Fabrika raporu üretince vault-içi terfi eder.","mevsim_tipi":"botanik","tek_satir":"Satürn'ün sessiz meşalesi; dik durmayı bilen bitki.","story_narrative":"Sığırkuyruğu, klasik gelenekte Satürn'ün bitkileri arasında sayılır — uzun, dik sapıyla tarlaların sessiz bekçisi gibidir. Yumuşak, tüylü yaprakları serte karşı yumuşaklığı temsil eder.\n\nEski kültürde sapları bir zamanlar meşale olarak kullanılmış; karanlıkta yol gösteren, sabırla yükselen bir bitki olarak hikâyelere girmiştir.","ritual":"Bugün sabırla ilerlediğin uzun bir işi düşün. Sığırkuyruğunun dik sapını hatırla: yavaş yükselen de göğe uzanır. (Bu bitkinin detayında güvenlik notu vardır.)"},{"herb_id":"mese","names":{"tr":"Meşe","en":"Oak","la":"Quercus robur"},"gezegen_birincil":"saturn","gezegen_ikincil":["gunes"],"celiski_notu":"Klasik gelenek ataması (vault-dışı). Meşe/Quercus geleneksel olarak Jüpiter'e de Satürn'e de yazılır; sert kabuk, uzun ömür ve dayanıklılık imzasıyla Satürn seçildi, Güneş (kraliyet/güç) ikincil.","kaynak_tipi":"klasik-gelenek-vault-disi","terfi_durumu":"bekliyor","agent_derin_kullanim":false,"beden_bolgeleri":["deri","mide-sindirim"],"tat":["buruk"],"enerjetik":{"isi":"provisional","nem":"kurutucu","durum":"klasik-gelenek"},"mevsim":["sonbahar"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"doğrulanmadı","not":"contraindications.json KAPSAMI DIŞI. Yüksek tanen içeriği; geleneksel olarak dış/yüzeysel kullanım. Toksik alkaloid yok. Bağımsız güvenlik doğrulaması önerilir (launch checklist)."},"kaynak_sayisi":0,"source_note":"Satürn rafı; vault-dışı klasik, terfi bekliyor.","mevsim_tipi":"botanik","tek_satir":"Zamanın omurgası; yüzyıllara kök salan sabır.","story_narrative":"Meşe, klasik gelenekte gücün ve dayanıklılığın ağacı olarak anılır — kimi zaman Satürn'ün sabrına, kimi zaman Güneş'in ihtişamına yazılır. Yavaş büyür ama yüzyıllar taşır.\n\nEski kültürlerde kutsal sayılmış, altında toplanılan ve söz verilen bir ağaç olmuş; sağlamlığın ve zamanın biriktirdiği değerin sembolü haline gelmiştir.","ritual":"Uzun vadede kök saldığın bir şeyi düşün — bir ilişki, bir beceri, bir alışkanlık. Meşe gibi: acele etmeyen, ama kalıcı olan. (Bu bitkinin detayında güvenlik notu vardır.)"},{"herb_id":"aslanpencesi","names":{"tr":"Aslanpençesi","en":"Lady's Mantle","la":"Alchemilla vulgaris"},"gezegen_birincil":"venus","gezegen_ikincil":["ay"],"celiski_notu":"Klasik gelenek ataması (vault-dışı). Alchemilla geleneksel olarak Venüs'e yazılır ('kadın otu'); yaprağında toplanan çiy damlası simya-Ay imgesiyle ikincil Ay.","kaynak_tipi":"klasik-gelenek-vault-disi","terfi_durumu":"bekliyor","agent_derin_kullanim":false,"beden_bolgeleri":["ureme-dongu"],"tat":["buruk"],"enerjetik":{"isi":"provisional","nem":"kurutucu","durum":"klasik-gelenek"},"mevsim":["yaz"],"mevsim_durum":"taslak-claude; mevsim-haritasi.json otorite; Türkan teyidi bekliyor","kozmik_olay":null,"guvenlik":{"app_safe":true,"guven_tier":null,"uyari_chip":null,"gebelik":"gebelikte geleneksel temkin (doğrulanmadı)","not":"contraindications.json KAPSAMI DIŞI. Geleneksel kadın-sağlığı bitkisi; gebelikte temkin geleneği vardır. Toksik alkaloid yok. Bağımsız güvenlik + gebelik doğrulaması önerilir (launch checklist)."},"kaynak_sayisi":0,"source_note":"Venüs rafı; vault-dışı klasik, terfi bekliyor. Döngü modülüyle bağı güçlü.","mevsim_tipi":"botanik","tek_satir":"Yaprağında çiy toplayan simyacı; Venüs'ün nazik eli.","story_narrative":"Aslanpençesi, klasik gelenekte Venüs'e yazılan narin bir bitkidir; yelpaze biçimli yaprakları sabah çiy damlalarını inci gibi toplar. Bu özelliği, eski simyacılar için değerli bir imge olmuştur.\n\nGeleneksel kültürde şefkat ve döngülerle ilişkilendirilmiş; sadeliğin içinde saklı bir zarafeti temsil eder.","ritual":"Sabah, bir yaprağın üzerindeki çiy damlasını — gerçek ya da hayalî — bir an seyret. Küçük şeylerin güzelliğini toplamak da bir bakım biçimidir. (Bu bitkinin detayında güvenlik notu vardır.)"}]$wseed$::jsonb) as e
on conflict (herb_id) do update set
  name_tr          = excluded.name_tr,
  gezegen_birincil = excluded.gezegen_birincil,
  app_safe         = excluded.app_safe,
  guven_tier       = excluded.guven_tier,
  data             = excluded.data,
  updated_at       = now();

-- ---------- quizzes (12) ----------
insert into public.quizzes (quiz_id, ay, title, data)
select
  e->>'quiz_id',
  (e->>'ay')::int,
  e->>'title',
  e->'data'
from jsonb_array_elements($wseed$[{"quiz_id":"ay1-disil-estetik","ay":1,"title":"Dişil Estetik Arketipin","data":{"_meta":{"belge":"quiz-ay1-disil-estetik","surum":"v0.1","tarih":"2026-07-05","kararlar":"Quiz yönü: EĞLENCE-ÖNDE (Onedio tonu), bilim arada (Türkan, 5 Tem). Ölçek yolu C: özgün maddeler, marka sesi — 'doğrulanmış test' iddiası YOK. Ay 1 = Dişil Estetik Arketip · Sonuç = Baskın + Yükselen (özgün format). Rotasyon revizyon ÖNERİSİ: Big Five → Ay 3'e (rotasyon finali Türkan'da).","hassasiyet":"Tasarım dosyası kuralı gömülü: kalıba sokan/yargılayan DEĞİL, güçlendirici öz-ifade. Açılış: 'Bunlar kalıp değil, ayna — hepsi sende var; bugün hangisi parlıyor, ona bakıyoruz.' Etiket: sembolik · eğlence amaçlı.","puanlama":"Her şık: p arketipine +2, s arketipine +1. En yüksek = Baskın, ikinci = Yükselen. Eşitlikte son cevaplanan sorudaki tercih kazanır.","gating":"Free: quiz + baskın/yükselen + kisa metin. Pro: derin_ek (gölge daveti) + astro-context overlay + yıl haritasına işlenir.","sinerji":"Her arketipin herbaryum bitkisi var (sonuç ekranı → 'Senin bitkin: X' → koleksiyon köprüsü).","paylasim":"Sonuç kartı R1.5 şablon hattı; yalnız arketip adı + tek_satir + paylasim cümlesi render edilir.","durum":"TASLAK-ONAYLI; TR polisaj launch checklist."},"acilis_metni":"Bunlar kalıp değil, ayna — hepsi sende var. Bugün hangisi parlıyor, ona bakıyoruz.","sonuc_sablonu":"Baskın: {A} · Yükselen: {B} — {A_tek_satir} Yükselen {B} enerjisi ise buna kendi dokunuşunu katıyor.","arketipler":{"siren":{"ad":"Siren","tek_satir":"Derin suların sesi; çekiciliğin gürültüden değil, derinlikten gelir.","kisa":"Siren enerjisi baskınken insanların sana yaklaşmak için sebebe ihtiyacı olmaz — sen başlı başına bir atmosfersin. Gücün, kendini ifade edişinde ve duygularının derinliğinde.","derin_ek":"Gölge daveti: derinliğin bazen seni kıyıdan koparabilir; ara sıra yüzeye çıkıp paylaşmak da bir güçtür.","bitki":"nilufer","paylasim":"Baskın arketipim: Siren — derinlik benim doğam."},"femme_fatale":{"ad":"Femme Fatale","tek_satir":"Keskin zarafet; gizemin bir duvar değil, seçilmiş bir kapı.","kisa":"Bu enerji sınır ve seçicilik demektir — herkes iç bahçene giremez. Soğukluk değil bu; kendi değerini bilmek.","derin_ek":"Gölge daveti: kontrol bazen yakınlığı geciktirebilir; güvendiğinde kapıyı aralamak zayıflık değildir.","bitki":"gul","paylasim":"Baskın arketipim: Femme Fatale — kapım seçtiklerime açık."},"ingenu":{"ad":"İngenü","tek_satir":"Sabah ışığı; merakın ve tazeliğin bulaşıcı.","kisa":"İngenü enerjisi dünyaya ilk kez bakar gibi bakmaktır — bu saflık değil, cesarettir.","derin_ek":"Gölge daveti: hep ışık olmak yorabilir; senin de gölgeli günlere hakkın var.","bitki":"papatya","paylasim":"Baskın arketipim: İngenü — merak benim süper gücüm."},"bohem":{"ad":"Bohem Ruh","tek_satir":"Rüzgârın kızı; kökün toprakta değil, özgürlüğünde.","kisa":"Bohem ruh kural tanımaz değil, kendi ritmini tanır. Estetiğin de hayatın da akışkan.","derin_ek":"Gölge daveti: akış güzeldir; ama bazen bir liman seçmek de özgürlüktür.","bitki":"lavanta","paylasim":"Baskın arketipim: Bohem Ruh — ritmim bana ait."},"kralice":{"ad":"Kraliçe","tek_satir":"Sofranın ve sözün sahibesi; varlığın düzen kurar.","kisa":"Kraliçe enerjisi otorite kurmak değil, herkesi rahat ettiren bir düzen kurmaktır — insanlar yanında güvende hisseder.","derin_ek":"Gölge daveti: herkesi taşımak tacı ağırlaştırır; senin de taşınmaya hakkın var.","bitki":"aslanpencesi","paylasim":"Baskın arketipim: Kraliçe — alanımı zarafetle tutarım."},"buyucu":{"ad":"Gizemli Büyücü","tek_satir":"Perdenin ardını gören; sezgin senin pusulan.","kisa":"Büyücü enerjisi görünmeyeni okur — atmosferleri, alt metinleri, işaretleri.","derin_ek":"Gölge daveti: hep okumak yorucudur; bazen bilmemeyi seçmek de bilgeliktir.","bitki":"adacayi","paylasim":"Baskın arketipim: Gizemli Büyücü — işaretleri okurum."},"vahsi":{"ad":"Vahşi Doğa","tek_satir":"Patikasız yürüyen; doğan evcilleşmeye gelmez.","kisa":"Vahşi Doğa enerjisi kuralsızlık değil, sahiciliktir — sınırlarını doğa gibi net çizersin.","derin_ek":"Gölge daveti: yaban kalp bazen yalnızlığı romantize eder; sürü de doğanın parçasıdır.","bitki":"isirgan","paylasim":"Baskın arketipim: Vahşi Doğa — sahicilik pazarlık kabul etmez."}},"sorular":[{"soru":"Hafta sonu için tek bilet var. Hangisi?","secenekler":[{"metin":"Deniz kenarında gün batımı yüzüşü","p":"buyucu"},{"metin":"Şehirde şık bir galeri gecesi","p":"femme_fatale"},{"metin":"Kır evinde reçel, battaniye, kitap","p":"bohem","s":"ingenu"},{"metin":"Ormanda patikasız bir yürüyüş","p":"vahsi"}]},{"soru":"Gardırobundan asla çıkmayacak parça?","secenekler":[{"metin":"Akışkan, dökümlü bir elbise","p":"siren"},{"metin":"Keskin kesimli, iddialı bir ceket","p":"femme_fatale"},{"metin":"Çiçekli, hafif bir yazlık","p":"ingenu"},{"metin":"Kat kat el yapımı takılar","p":"bohem"}]},{"soru":"Bir davette seni nerede buluruz?","secenekler":[{"metin":"Piyanonun yanında, bir hikâye anlatırken","p":"siren"},{"metin":"Bir kenarda, üç dakikada herkesi çözmüşken","p":"buyucu","s":"femme_fatale"},{"metin":"Ev sahibine yardım edip herkesi rahat ettirirken","p":"kralice"},{"metin":"Balkonda, yıldızlara bakan küçük grupla","p":"bohem"}]},{"soru":"Telefon galerin en çok neyle dolu?","secenekler":[{"metin":"Gökyüzü ve ay fotoğrafları","p":"buyucu"},{"metin":"Kahkaha anları, spontane kareler","p":"ingenu"},{"metin":"Yollar, haritalar, gidilecek yerler","p":"vahsi","s":"bohem"},{"metin":"Kusursuz kadrajlar: çiçek, fincan, ışık","p":"kralice","s":"femme_fatale"}]},{"soru":"Flört dilin hangisi?","secenekler":[{"metin":"Derin göz teması, az söz","p":"femme_fatale"},{"metin":"Espri ve oyunbazlık","p":"ingenu"},{"metin":"Gece yarısına sarkan uzun konuşmalar","p":"siren"},{"metin":"Doğal akış — olursa olur rahatlığı","p":"bohem"}]},{"soru":"Ay ışığında bir bahçedesin. İlk ne yaparsın?","secenekler":[{"metin":"Çıplak ayak toprağa basarım","p":"vahsi"},{"metin":"Bitkilere dokunur, kokularını içime çekerim","p":"buyucu"},{"metin":"Ayın altında sessizce otururum","p":"bohem"},{"metin":"Çiçeklerden kendime küçük bir taç yaparım","p":"ingenu"}]},{"soru":"İçeceğin hangisi?","secenekler":[{"metin":"Zarif bir fincanda, seremonisiyle demli çay","p":"kralice"},{"metin":"Buz gibi taze nane-limon","p":"vahsi"},{"metin":"Koyu, yoğun bir sıcak çikolata","p":"femme_fatale"},{"metin":"Yasemin kokulu hafif bir çay","p":"siren"}]},{"soru":"İnsanlar seni ilk tanıdığında genelde ne der?","secenekler":[{"metin":"\"Sana bir şey anlatasım geliyor\"","p":"kralice"},{"metin":"\"Aklımdan geçeni nasıl bildin?\"","p":"buyucu"},{"metin":"\"Enerjin çok ferah\"","p":"ingenu"},{"metin":"\"Seni çözemedim ama merak ediyorum\"","p":"femme_fatale"}]},{"soru":"Zor bir günün sonunda seni ne toparlar?","secenekler":[{"metin":"Uzun, köpüklü bir banyo","p":"siren"},{"metin":"Her şeyi kapatıp doğaya kaçmak","p":"vahsi"},{"metin":"Mum yakıp günlüğüme yazmak","p":"buyucu"},{"metin":"Sevdiklerimi toplayıp sofra kurmak","p":"kralice"}]},{"soru":"Bir süper gücün olsaydı?","secenekler":[{"metin":"Sesimle sakinleştirmek","p":"siren"},{"metin":"Görünmeden gözlemlemek","p":"femme_fatale"},{"metin":"Bitkilerle konuşmak","p":"vahsi","s":"buyucu"},{"metin":"Dokunduğumu neşelendirmek","p":"ingenu"}]}]}},{"quiz_id":"ay2-tanrica","ay":2,"title":"İçindeki Tanrıça","data":{"_meta":{"belge":"quiz-ay2-tanrica","surum":"v0.1","tarih":"2026-07-05","hassasiyet":"Güçlendirici çerçeve; 'kalıp değil ayna' açılışı Ay 1 ile ortak. Mitoloji kamu malı; Bolen metni KOPYALANMADI, kavramlar özgün yazıldı. Etiket: sembolik · eğlence amaçlı.","puanlama":"Ay 1 ile aynı: p +2, s +1; Baskın + Yükselen.","gating":"Free: baskın/yükselen + kisa. Pro: derin_ek (gölge daveti) + astro overlay.","sinerji":"Tanrıça→bitki köprüsü (Artemis→söğüt, Athena→ceviz, Hestia→biberiye, Hera→ıhlamur, Demeter→rezene, Persephone→menekşe [mitolojik doğru: Persephone menekşe toplarken], Afrodit→gül [klasik]).","durum":"TASLAK-ONAYLI; TR polisaj launch checklist."},"acilis_metni":"Bunlar kalıp değil, ayna — hepsi sende var. Bugün hangisi tahtta, ona bakıyoruz.","sonuc_sablonu":"Baskın: {A} · Yükselen: {B} — {A_tek_satir} Yükselen {B} ise sahneye kendi rengini katıyor.","arketipler":{"artemis":{"ad":"Artemis","tek_satir":"Kendi ormanının kraliçesi; yönünü yıldızlardan değil, içinden alırsın.","kisa":"Artemis enerjisi bağımsızlıktır — yalnızlık değil, öz-yeterlilik. Kendi patikanı açar, kendi ritminde yürürsün.","derin_ek":"Gölge daveti: hedefe kilitlenmek bazen yol arkadaşlarını görmeyi unutturur; ara sıra kampı paylaşmak avı küçültmez.","bitki":"sogut","paylasim":"Baskın tanrıçam: Artemis — patikamı kendim açarım."},"athena":{"ad":"Athena","tek_satir":"Zihnin zırhı ve zeytin dalı; stratejin şefkatle keskin.","kisa":"Athena enerjisi berrak akıldır — kaosun ortasında planı görebilen göz. Bilgi senin için süs değil, araç.","derin_ek":"Gölge daveti: her şeyi çözmek zorunda değilsin; bazen kalbin de söz alsın.","bitki":"ceviz","paylasim":"Baskın tanrıçam: Athena — aklım pusulam."},"hestia":{"ad":"Hestia","tek_satir":"Ocağın sessiz alevi; huzur senin doğal halin.","kisa":"Hestia enerjisi merkezde kalabilmektir — dış dünya ne kadar hızlanırsa hızlansın, içindeki ateş sakin ve sabit yanar.","derin_ek":"Gölge daveti: iç dünyan güvenli; ama kapıyı ara sıra aralamak onu bozmaz.","bitki":"biberiye","paylasim":"Baskın tanrıçam: Hestia — huzurum içeriden."},"hera":{"ad":"Hera","tek_satir":"Bağın mimarı; sadakatin bir zincir değil, seçilmiş bir taç.","kisa":"Hera enerjisi derin bağlılıktır — ortaklığa, söze, birlikte kurulan hayata verdiğin ağırlık senin gücün.","derin_ek":"Gölge daveti: ilişkiye verdiğin emeği kendine de ver; taç önce kendi başında durmalı.","bitki":"ihlamur","paylasim":"Baskın tanrıçam: Hera — bağlarım bilinçli seçimim."},"demeter":{"ad":"Demeter","tek_satir":"Besleyen toprak; büyüttüğün her şey senin imzan.","kisa":"Demeter enerjisi büyütmektir — insan, bitki, fikir fark etmez; elinin değdiği serpilir.","derin_ek":"Gölge daveti: hasat mevsiminde kendi tabağını da doldur; besleyenin de beslenmeye hakkı var.","bitki":"rezene","paylasim":"Baskın tanrıçam: Demeter — büyütmek benim dilim."},"persephone":{"ad":"Persephone","tek_satir":"İki dünyanın kızı; karanlığı da baharı da tanırsın.","kisa":"Persephone enerjisi dönüşümdür — inişleri yok saymazsın; her inişten bir baharla dönersin. Derinlik seni korkutmaz.","derin_ek":"Gölge daveti: derinlik senin evin; ama yüzeyin çiçekleri de senin. İkisi arasında köprü kur.","bitki":"menekse","paylasim":"Baskın tanrıçam: Persephone — her kışım bir baharla biter."},"afrodit":{"ad":"Afrodit","tek_satir":"Deniz köpüğünden doğan; güzellik senin dilin, yaratmak nefesin.","kisa":"Afrodit enerjisi hayat sevincidir — güzelliği tüketmez, üretirsin; dokunduğun şey canlanır.","derin_ek":"Gölge daveti: sevilmek için parlamana gerek yok; olduğun ışık yeter.","bitki":"gul","paylasim":"Baskın tanrıçam: Afrodit — güzellik benim dilim."}},"sorular":[{"soru":"İdeal tatilin?","secenekler":[{"metin":"Tek başıma dağda kamp","p":"artemis"},{"metin":"Müze ve mimari turu","p":"afrodit"},{"metin":"Evde kendime kurduğum bir spa haftası","p":"hestia"},{"metin":"Sevdiğimle özel bir kaçamak","p":"hera","s":"afrodit"}]},{"soru":"Arkadaş grubundaki rolün?","secenekler":[{"metin":"Planı kuran stratejist","p":"hera"},{"metin":"Herkesi doyuran, kollayan","p":"demeter"},{"metin":"Kriz anında sakin liman","p":"hestia"},{"metin":"Gruba hayat ve yeni insan katan","p":"afrodit"}]},{"soru":"Bir süper güç seç:","secenekler":[{"metin":"Olacakları önceden sezmek","p":"persephone"},{"metin":"Her tartışmayı kazanmak","p":"athena"},{"metin":"Dokunduğum bitkiyi büyütmek","p":"demeter"},{"metin":"Görünmeden ormanda kaybolmak","p":"artemis"}]},{"soru":"Zor bir karar anında ilk hamlen?","secenekler":[{"metin":"Artı-eksi listesi çıkarırım","p":"athena"},{"metin":"İçime çekilir, işareti beklerim","p":"persephone"},{"metin":"Güvendiğim kişiyle konuşurum","p":"hera"},{"metin":"Yürüyüşe çıkarım, yol gösterir","p":"artemis"}]},{"soru":"Evindeki favori köşen?","secenekler":[{"metin":"Mutfak — ocağın başı","p":"hestia","s":"demeter"},{"metin":"Çalışma masam","p":"athena"},{"metin":"Balkon, bitkilerimin yanı","p":"demeter"},{"metin":"Loş, yumuşak inziva köşem","p":"persephone"}]},{"soru":"Bir ilişkide seni en çok ne besler?","secenekler":[{"metin":"Derin, sarsılmaz sadakat","p":"hera"},{"metin":"Tutku ve oyunbaz yakınlık","p":"afrodit"},{"metin":"Birlikte susabilmek","p":"hestia"},{"metin":"Kişisel alanıma saygı","p":"artemis"}]},{"soru":"Hafta sonu sabahın?","secenekler":[{"metin":"Erken doğa koşusu","p":"artemis"},{"metin":"Sevdiklerimle uzun kahvaltı","p":"demeter","s":"hera"},{"metin":"Tek başıma kitap ve kahve","p":"hestia"},{"metin":"Atölye, boya, yaratıcı dağınıklık","p":"afrodit","s":"athena"}]},{"soru":"İnsanlar sana en çok ne için gelir?","secenekler":[{"metin":"Akıl danışmaya","p":"athena"},{"metin":"Dertleşmeye, şefkate","p":"demeter"},{"metin":"Moral ve hayat enerjisi almaya","p":"afrodit"},{"metin":"Sır emanet etmeye","p":"persephone"}]},{"soru":"Dönüşüm senin için nasıl olur?","secenekler":[{"metin":"Her kışım bir baharla biter","p":"persephone"},{"metin":"Hedef koyar, adım adım dönüşürüm","p":"athena"},{"metin":"Sevgiyle, ilişki içinde yumuşayarak","p":"hera"},{"metin":"Ellerimi toprağa sokunca","p":"demeter"}]},{"soru":"Gece göğünde seni ne çağırır?","secenekler":[{"metin":"İnce hilal","p":"artemis"},{"metin":"Dolunayın sakladığı sır","p":"persephone"},{"metin":"Yıldız haritasının düzeni","p":"athena"},{"metin":"Ay ışığının denizdeki yolu","p":"afrodit"}]}]}},{"quiz_id":"ay3-kisilik-pusulasi","ay":3,"title":"Kişilik Pusulan","data":{"_meta":{"puanlama":"p +2, s +1; Baskın+Yükselen.","durum":"TASLAK-ONAYLI; TR polisaj checklist.","belge":"quiz-ay3-kisilik-pusulasi","surum":"v0.1","tarih":"2026-07-05","KATMAN":"A-BİLİM. Big Five (Beş Faktör) modelinden ESİNLENMİŞTİR. 'Doğrulanmış/klinik kişilik testi' DEĞİLDİR ve öyle sunulamaz — sembolik/eğlence amaçlı öz-yansıtma aracı.","ic_kaynak":"Yapı: Beş Faktör Kişilik Modeli (Costa & McCrae geleneği; TR-doğrulanmış kısa formlar BFI-10/QBF referans). Maddeler ÖZGÜN yazıldı (telif temiz), psikometrik re-validasyon YAPILMADI. Ticari kullanımda ölçek-lisansı kontrolü gereksiz (özgün madde) ama 'esinlenen' ibaresi zorunlu.","FORMAT_FARKI":"Diğer aylardan farklı: 7 arketip DEĞİL, 5 BOYUT PROFİLİ. Her boyutta düşük/orta/yüksek + sembolik-nötr etiket (tip yanılsaması kurmadan). Zayıf-nokta düzeltmesi: Big Five sürekli boyuttur, arketip formatına zorlamak bilimsel yanıltıcı olurdu.","puanlama_ozel":"Her boyut ayrı skorlanır (2 soru, +/- yön). Boyut skoru → düşük(<40%)/orta/yüksek(>60%) + ilgili etiket. Sonuç = 5 boyut profili, tek 'kazanan' yok.","gating":"Free: 5 boyut yüzde + etiketler. Pro: derin_ek + boyutların astro-context yorumu + yıl haritasına işlenir.","hassasiyet":"Etiketler NÖTR ve güçlendirici (her iki uç da değerli çerçevesi); 'iyi/kötü' boyut yok. 'Bunlar kalıp değil, ayna.'"},"acilis_metni":"Bu bir sınav değil, bir ayna — iyisi ya da kötüsü yok, sadece sen varsın. Beş pusulanın nereyi gösterdiğine bakıyoruz.","sonuc_yapisi":"5 boyutun her biri: {ad} — %{skor}, etiket: {yuksek/dusuk etiket}, {metin}. Kapanış: bu bir fotoğraf, kimliğin değil; zamanla değişebilir.","boyutlar":{"aciklik":{"ad":"Açıklık","yuksek":"Meraklı Kâşif","dusuk":"Sağlam Gelenek","yuksek_metin":"Yeniye, hayale, farklı fikirlere açıksın. Rutinden çok keşif seni besler.","dusuk_metin":"Bildik, denenmiş, somut olanda güven bulursun. İstikrar senin gücün.","derin_ek":"İki uç da değerli; açıklık ilham verir, köklülük taşır."},"sorumluluk":{"ad":"Sorumluluk","yuksek":"Düzen Mimarı","dusuk":"Akış Ustası","yuksek_metin":"Planlı, disiplinli, hedefe kilitli. Söz verdiğinde yaparsın.","dusuk_metin":"Esnek, spontane, ana açık. Katı plan seni sıkar, akış sana yakışır.","derin_ek":"Düzen güven verir, esneklik özgürlük; hangisi baskınsa, ara sıra öbürünü denemek de iyi gelir."},"disadonukluk":{"ad":"Dışadönüklük","yuksek":"Sosyal Güneş","dusuk":"Dingin Ay","yuksek_metin":"İnsanlarla, hareketle, hayatın uğultusuyla dolarsın. Kalabalık seni yormaz; aksine doldurur.","dusuk_metin":"Sakinlik, yalnızlık, derin ikili sohbet seni besler. İç dünyan zengin.","derin_ek":"İkisi de sağlıklı; önemli olan enerjini nerede topladığını bilmek."},"uyumluluk":{"ad":"Uyumluluk","yuksek":"Şefkatli Köprü","dusuk":"Net Sınır","yuksek_metin":"Empati, uyum, işbirliği senin dilin. İnsanları önemser, köprü kurarsın.","dusuk_metin":"Dürüstlük, sınır, öz-savunma senin gücün. Herkesi memnun etme derdin yok.","derin_ek":"Şefkat bağ kurar, sınır korur; sağlıklı denge ikisini de ister."},"duygusallik":{"ad":"Duygusal Hassasiyet","yuksek":"Derin Hisseden","dusuk":"Sakin Liman","yuksek_metin":"Duyguları derin ve yoğun yaşarsın. Bu bir kırılganlık değil, zengin bir iç dünya.","dusuk_metin":"Duygusal olarak sakin ve dengeli. Fırtınalarda soğukkanlılığını korursun.","derin_ek":"Derin hissetmek de sakin kalmak da birer güç; birinin diğerinden üstünlüğü yok."}},"sorular":[{"soru":"Yeni bir yere seyahatte planın?","secenekler":[{"metin":"Detaylı program çıkarırım","boyut":"sorumluluk","yon":"+"},{"metin":"Akışına bırakırım","boyut":"sorumluluk","yon":"-"}]},{"soru":"Boş bir hafta sonu?","secenekler":[{"metin":"Yeni bir şey denerim","boyut":"aciklik","yon":"+"},{"metin":"Bildiğim rahat rutinime dönerim","boyut":"aciklik","yon":"-"}]},{"soru":"Kalabalık bir partiden sonra?","secenekler":[{"metin":"Enerji dolu hissederim","boyut":"disadonukluk","yon":"+"},{"metin":"Yorulur, yalnızlığa kaçarım","boyut":"disadonukluk","yon":"-"}]},{"soru":"Bir anlaşmazlıkta?","secenekler":[{"metin":"Uzlaşı ve uyum ararım","boyut":"uyumluluk","yon":"+"},{"metin":"Görüşümü net savunurum","boyut":"uyumluluk","yon":"-"}]},{"soru":"Zor bir haber karşısında?","secenekler":[{"metin":"Derinden etkilenirim, uzun süre içimde taşırım","boyut":"duygusallik","yon":"+"},{"metin":"Sakin kalır, çabuk toparlarım","boyut":"duygusallik","yon":"-"}]},{"soru":"İş/görev tarzın?","secenekler":[{"metin":"Listeler, düzen; işim son tarihten önce biter","boyut":"sorumluluk","yon":"+"},{"metin":"Son ana esnek, ilhamla çalışırım","boyut":"sorumluluk","yon":"-"}]},{"soru":"Sanat/fikir dünyası?","secenekler":[{"metin":"Soyut, felsefi, hayali severim","boyut":"aciklik","yon":"+"},{"metin":"Somut, pratik, işe yararı severim","boyut":"aciklik","yon":"-"}]},{"soru":"Bir grupta genelde?","secenekler":[{"metin":"Konuşan, başlatan benim","boyut":"disadonukluk","yon":"+"},{"metin":"Dinleyen, gözlemleyen benim","boyut":"disadonukluk","yon":"-"}]},{"soru":"Biri yardım istediğinde?","secenekler":[{"metin":"Kendi işimi bırakır, koşarım","boyut":"uyumluluk","yon":"+"},{"metin":"Sınırımı korur, gerçekçi olurum","boyut":"uyumluluk","yon":"-"}]},{"soru":"Stresli dönemde?","secenekler":[{"metin":"Kaygı ve duygular yoğunlaşır","boyut":"duygusallik","yon":"+"},{"metin":"Genelde dengede kalırım","boyut":"duygusallik","yon":"-"}]}]}},{"quiz_id":"ay4-element","ay":4,"title":"Elementin","data":{"_meta":{"puanlama":"p +2, s +1; Baskın+Yükselen. Eşitlikte son soru.","durum":"TASLAK-ONAYLI; TR polisaj checklist.","hassasiyet":"'Kalıp değil ayna' açılışı ortak; güçlendirici çerçeve. Etiket: sembolik · eğlence amaçlı.","belge":"quiz-ay4-element","surum":"v0.1","tarih":"2026-07-05","ozel_sinerji":"Element→bitki köprüsü + PRO element-denge lensiyle sinerji (koleksiyonun element dağılımı). 4 arketip (klasik unsur).","gating":"Free: element+kisa+bitki. Pro: derin_ek + element-denge lensi + astro overlay."},"acilis_metni":"Bunlar kalıp değil, ayna — dört unsur da sende var. Bugün hangisi baskın, ona bakıyoruz.","sonuc_sablonu":"Baskın: {A} {A_glif} · Yükselen: {B} — {A_tek_satir} (Senin bitkin: {A_bitki}.)","arketipler":{"ates":{"ad":"Ateş","glif":"🜂","tek_satir":"İçinde sönmeyen bir kıvılcım var; harekete geçiren sensin.","kisa":"Ateş enerjisi tutku ve cesarettir — başlatır, ısıtır, ilham verirsin. Durgunluk sana göre değil.","derin_ek":"Gölge daveti: alevin güçlü; ara sıra dinlenmek onu söndürmez, korur.","bitki":"zencefil","paylasim":"Elementim Ateş — kıvılcım bende."},"toprak":{"ad":"Toprak","glif":"🜃","tek_satir":"Sağlam ve besleyicisin; insanların güvenle bastığı zemin.","kisa":"Toprak enerjisi istikrar ve bolluktur — köklü, güvenilir, verimli. Sözün senettir.","derin_ek":"Gölge daveti: sağlam olmak güzel; ama toprak en çok sürüldüğünde verir — değişim düşman değil.","bitki":"atkuyrugu","paylasim":"Elementim Toprak — güvenli zeminim."},"hava":{"ad":"Hava","glif":"🜁","tek_satir":"Zihin ve özgürlük taşırsın; fikirlerin rüzgâr gibi dolaşır.","kisa":"Hava enerjisi düşünce ve iletişimdir — meraklı, esnek, sosyal. Bağ kurar, ilham dağıtırsın.","derin_ek":"Gölge daveti: zihnin uçarken bedenini de yere indir.","bitki":"lavanta","paylasim":"Elementim Hava — fikirlerim rüzgâr gibi."},"su":{"ad":"Su","glif":"🜄","tek_satir":"Derin ve sezgiselsin; duyguların gücün, akışın yolun.","kisa":"Su enerjisi duygu ve sezgidir — derin, şefkatli, uyumlu. Hisseder, sarar, yumuşatırsın.","derin_ek":"Gölge daveti: her duyguyu sünger gibi çekmek zorunda değilsin; ara sıra kıyıya çıkmak da suya dahil.","bitki":"nilufer","paylasim":"Elementim Su — derinlik benim doğam."}},"sorular":[{"soru":"Yeni bir projeye nasıl başlarsın?","secenekler":[{"metin":"Hemen atlar, yaparak öğrenirim","p":"ates"},{"metin":"Plan yapar, adım adım ilerlerim","p":"toprak"},{"metin":"Önce araştırır, fikir toplarım","p":"hava"},{"metin":"İçime sorar, doğru hissi beklerim","p":"su"}]},{"soru":"Arkadaş grubunda rolün?","secenekler":[{"metin":"Ateşleyen, harekete geçiren","p":"ates"},{"metin":"Güvenilen, kollayan","p":"toprak"},{"metin":"Fikir üreten, bağ kuran","p":"hava"},{"metin":"Dinleyen, derinleştiren","p":"su"}]},{"soru":"Stresini nasıl atarsın?","secenekler":[{"metin":"Spor, hareket, ter","p":"ates"},{"metin":"Doğada, toprakta","p":"toprak"},{"metin":"Konuşarak, yazarak","p":"hava"},{"metin":"Suyla, banyoyla, ağlayarak","p":"su"}]},{"soru":"Seni ne besler?","secenekler":[{"metin":"Yeni maceralar","p":"ates"},{"metin":"Rutin ve güven","p":"toprak"},{"metin":"Yeni fikirler, sohbet","p":"hava"},{"metin":"Derin bağlar","p":"su"}]},{"soru":"Karar verirken?","secenekler":[{"metin":"İçgüdüyle, hızlı","p":"ates"},{"metin":"Pratik, mantıklı","p":"toprak"},{"metin":"Tüm açıları tartarak","p":"hava"},{"metin":"Sezgiyle","p":"su"}]},{"soru":"İdeal ortamın?","secenekler":[{"metin":"Canlı, hareketli","p":"ates"},{"metin":"Doğal, sakin","p":"toprak"},{"metin":"Açık, sosyal","p":"hava"},{"metin":"Su kenarı, dingin","p":"su"}]},{"soru":"Zorlukta ilk tepkin?","secenekler":[{"metin":"Savaşırım","p":"ates"},{"metin":"Sağlam dururum","p":"toprak"},{"metin":"Çözüm ararım","p":"hava"},{"metin":"Hissederim, sonra hareket ederim","p":"su"}]},{"soru":"Gece göğünde seni ne çeker?","secenekler":[{"metin":"Kayan yıldızın ateşi","p":"ates"},{"metin":"Sabit, güvenli takımyıldızlar","p":"toprak"},{"metin":"Rüzgârdaki bulutlar","p":"hava"},{"metin":"Ayın sudaki yolu","p":"su"}]}]}},{"quiz_id":"ay5-bitki","ay":5,"title":"Ruh Bitkin","data":{"_meta":{"belge":"quiz-ay5-bitki","surum":"v0.1","tarih":"2026-07-05","ozel_sinerji":"EN GÜÇLÜ HERBARYUM CROSS-SELL AYI. Arketip = bitkinin kendisi; sonuç doğrudan koleksiyondaki bir kart. Sonuç ekranı → 'Ruh bitkin: X' → o kart herbaryumda KALICI 'ruh bitkin' rozeti + parlama kazanır (tekrar-değeri + koleksiyon bağı). Diğer aylardan farkı: bitki köprüsü ayrı bir bitkiye DEĞİL, sonucun kendisine gider.","secim_mantigi":"37 havuzdan klasik 7 gezegeni tam temsil eden 7 bitki (motor tabloyla %100 tutarlı: papatya=Ay, biberiye=Güneş, lavanta=Merkür, gül=Venüs, ısırgan=Mars, karahindiba=Jüpiter, atkuyruğu=Satürn). Veto-açık. v2 genişleme adayı: element bazlı ikinci 7'li.","hassasiyet":"'Kalıp değil ayna' açılışı ortak. Bitki karakterleri sembolik (geleneksel enerji); doz/tüketim/tıbbi iddia YOK. Etiket: sembolik · eğlence amaçlı.","puanlama":"p +2, s +1; Baskın (=ruh bitkin) + Yükselen. Eşitlikte son soru tercihi.","gating":"Free: ruh bitkin + kisa + koleksiyon rozeti. Pro: derin_ek (gölge daveti) + astro overlay + o bitkinin gezegen-günü içeriği.","durum":"TASLAK-ONAYLI; TR polisaj launch checklist."},"acilis_metni":"Bunlar kalıp değil, ayna — hepsi sende var. Bugün hangi bitki sende en çok konuşuyor, ona bakıyoruz.","sonuc_sablonu":"Ruh bitkin: {A} {A_glif} · Yükselen: {B} — {A_tek_satir} Yükselen {B} enerjisi de sana eşlik ediyor. (Bu kart artık bahçende özel parlıyor.)","arketipler":{"papatya":{"ad":"Papatya","glif":"☾ Ay","tek_satir":"Sen sakin bir sığınaksın; telaşın ortasında insanların nefes aldığı yer.","kisa":"Papatya ruhu sükûnettir — gösterişsiz ama vazgeçilmez. İnsanlar yanında yavaşlar, güvenir. Gücün yumuşaklığında.","derin_ek":"Gölge daveti: herkesi sakinleştirirken kendi fırtınanı bastırma; senin de dalgalanmaya hakkın var.","paylasim":"Ruh bitkim: Papatya — sakin bir sığınağım."},"biberiye":{"ad":"Biberiye","glif":"☉ Güneş","tek_satir":"Sen canlı bir hafızasın; sadakatin ve ışığın yıllara direnir.","kisa":"Biberiye ruhu diri kalmaktır — kışın bile yeşil. Hatırlarsın, sadıksın, kolay kolay solmazsın. Kokun bile iz bırakır.","derin_ek":"Gölge daveti: her şeyi hatırlamak bazen ağırdır; bazı şeyleri bırakmak da bir tazelenme.","paylasim":"Ruh bitkim: Biberiye — ışığım kışın bile yeşil."},"lavanta":{"ad":"Lavanta","glif":"☿ Merkür","tek_satir":"Sen bir akşam huzurusun; kalabalık zihinleri durultursun.","kisa":"Lavanta ruhu berraklıktır — telaşlı bir günün sonunda gözün dinlendiği yer. Dağınık zihinler senin yanında toparlanır.","derin_ek":"Gölge daveti: herkesin huzuru olurken kendi kokunu unutma; sana da dinlenmek düşer.","paylasim":"Ruh bitkim: Lavanta — kalabalığı durultan huzur."},"gul":{"ad":"Gül","glif":"♀ Venüs","tek_satir":"Sen hem açık hem sınırlısın; güzelliğin dikeniyle birlikte gelir.","kisa":"Gül ruhu zarafet ve öz-değerdir — kalbin açık ama sınırların net. Sevmeyi de korunmayı da aynı anda bilirsin.","derin_ek":"Gölge daveti: dikenlerin seni korur ama bazen yaklaşmak isteyeni de uzaklaştırır; güvendiğinde açılmak cesarettir.","paylasim":"Ruh bitkim: Gül — kalbim açık, sınırım net."},"isirgan":{"ad":"Isırgan","glif":"♂ Mars","tek_satir":"Sen sahici bir güçsün; dokunulmayı beklemez, mesafeni hissettirirsin.","kisa":"Isırgan ruhu sınır ve sahiciliktir — yaklaşana mesafesini gösterir ama tanıyana cömert bir dosttur. Yumuşamadan koruyabilirsin.","derin_ek":"Gölge daveti: sürekli kalkan olmak yorar; doğru ellerde dikensiz de kalabilirsin.","paylasim":"Ruh bitkim: Isırgan — sahiciliğim pazarlık kabul etmez."},"karahindiba":{"ad":"Karahindiba","glif":"♃ Jüpiter","tek_satir":"Sen özgür bir dileksin; tutunmayı değil, rüzgâra bırakmayı bilirsin.","kisa":"Karahindiba ruhu özgürlük ve cömertliktir — biriktirmez, dağıtırsın. Nereye düşsen kök salar, her yerde çiçek açarsın.","derin_ek":"Gölge daveti: hep akıp gitmek güzeldir; ama bazen bir yere kök salmak da özgürlüğün parçası.","paylasim":"Ruh bitkim: Karahindiba — dileğimi rüzgâra bırakırım."},"atkuyrugu":{"ad":"Atkuyruğu","glif":"♄ Satürn","tek_satir":"Sen kadim bir omurgasın; yavaş büyür, sağlam durursun.","kisa":"Atkuyruğu ruhu sabır ve yapıdır — milyonlarca yıldır ayakta. Gösteriş değil, dayanıklılık. Fırtınada bükülür ama kırılmazsın.","derin_ek":"Gölge daveti: sağlam olmak zorunda değilsin her an; bazen eğilmek de gücün bir hali.","paylasim":"Ruh bitkim: Atkuyruğu — yavaş büyüyen, sağlam duran."}},"sorular":[{"soru":"Bir arkadaşın kriz anında seni arar. İlk tepkin?","secenekler":[{"metin":"Sakinleştiririm, 'nefes al, buradayım' derim","p":"papatya"},{"metin":"Dinler, net bir çözüm planı çıkarırım","p":"lavanta","s":"atkuyrugu"},{"metin":"'Yanındayım, kimse sana dokunamaz' derim","p":"isirgan"},{"metin":"Perspektif veririm: 'bu da geçer, büyük resme bak'","p":"karahindiba"}]},{"soru":"İdeal bir gün sonu?","secenekler":[{"metin":"Sıcak banyo, loş ışık, sessizlik","p":"lavanta"},{"metin":"Sevdiklerimle, kahkahayla dolu bir sofra","p":"biberiye"},{"metin":"Doğada tek başıma bir yürüyüş","p":"isirgan","s":"karahindiba"},{"metin":"Mum, günlük, kendimle baş başa","p":"papatya"}]},{"soru":"İnsanlar seni ilk tanıdığında ne hisseder?","secenekler":[{"metin":"Ferahlık, huzur","p":"lavanta"},{"metin":"Sıcaklık, güven","p":"biberiye"},{"metin":"Merak — 'seni çözemedim'","p":"gul"},{"metin":"Saygılı mesafe","p":"isirgan"}]},{"soru":"Sınır koyman gerektiğinde?","secenekler":[{"metin":"Nazikçe ama net söylerim","p":"gul"},{"metin":"Açıkça, tereddütsüz","p":"isirgan"},{"metin":"Sessizce geri çekilirim","p":"papatya"},{"metin":"Esnerim ama kırılmam","p":"atkuyrugu"}]},{"soru":"Hangi ev köşesi seninle özdeş?","secenekler":[{"metin":"Bitkilerle dolu ferah balkon","p":"karahindiba"},{"metin":"Kitaplı, sakin okuma köşesi","p":"atkuyrugu"},{"metin":"Işıklı, canlı mutfak","p":"biberiye"},{"metin":"Yumuşak, loş dinlenme köşesi","p":"papatya","s":"lavanta"}]},{"soru":"Bir hayalin nasıl gerçeğe döner?","secenekler":[{"metin":"Sabırla, adım adım, yıllara yayarak","p":"atkuyrugu"},{"metin":"Bırakırım, doğru zamanda kendi gelir","p":"karahindiba"},{"metin":"Kalbimin sesini takip ederek","p":"gul"},{"metin":"İnatla, kışın bile vazgeçmeyerek","p":"biberiye"}]},{"soru":"Zor bir duyguyla nasıl baş edersin?","secenekler":[{"metin":"Kendime yumuşak davranır, geçmesini beklerim","p":"papatya"},{"metin":"Düşüncelerimi yazıya döker, zihnimi durulturum","p":"lavanta"},{"metin":"Doğaya çıkar, toprakta boşaltırım","p":"isirgan"},{"metin":"Büyük resme bakar, hafiflerim","p":"karahindiba"}]},{"soru":"Seni en iyi anlatan söz?","secenekler":[{"metin":"'Yavaş büyüyen, sağlam durur'","p":"atkuyrugu"},{"metin":"'Kışın bile yeşil kalırım'","p":"biberiye"},{"metin":"'Açığım ama sınırlıyım'","p":"gul"},{"metin":"'Telaşı yavaşlatırım'","p":"papatya"}]},{"soru":"Bir grupta seni nerede buluruz?","secenekler":[{"metin":"Ortamı yatıştıran, herkesi rahat ettiren","p":"lavanta"},{"metin":"Enerji veren, hikâye anlatan","p":"biberiye"},{"metin":"Kenarda, gözlemleyen, seçici","p":"gul"},{"metin":"Kendi köşesinde, bağımsız","p":"isirgan","s":"karahindiba"}]},{"soru":"Gece göğüne baktığında gözün nerede kalır?","secenekler":[{"metin":"Ayın yumuşak ışığı","p":"papatya"},{"metin":"Sabırla dönen takımyıldızlar","p":"atkuyrugu"},{"metin":"Rüzgârda savrulan bulutlar","p":"karahindiba"},{"metin":"Günbatımının son turuncusu","p":"biberiye"}]}]}},{"quiz_id":"ay6-ayfazi","ay":6,"title":"Ay Fazın","data":{"_meta":{"puanlama":"p +2, s +1; Baskın+Yükselen. Eşitlikte son soru.","durum":"TASLAK-ONAYLI; TR polisaj checklist.","hassasiyet":"'Kalıp değil ayna' açılışı ortak; güçlendirici çerçeve. Etiket: sembolik · eğlence amaçlı.","belge":"quiz-ay6-ayfazi","surum":"v0.1","tarih":"2026-07-05","ozel_sinerji":"KOZMOS + Gece Açanlar sinerjisi: ay fazı kimliği, kozmik kart mekaniğiyle tematik uyum. 4 faz arketipi.","gating":"Free: faz+kisa. Pro: derin_ek + gerçek anlık ay fazınla karşılaştırma + astro overlay."},"acilis_metni":"Bunlar kalıp değil, ayna — ay gibi sen de tüm fazları taşırsın. Bugün hangisinin ışığındasın, ona bakıyoruz.","sonuc_sablonu":"Baskın: {A} · Yükselen: {B} — {A_tek_satir}","arketipler":{"yeniay":{"ad":"Yeni Ay","tek_satir":"Sen bir başlangıçsın; boş sayfanın ve niyet tohumunun enerjisi.","kisa":"Yeni ay enerjisi potansiyeldir — henüz görünmeyen ama filizlenmeye hazır. Başlatmayı, hayal etmeyi seversin.","derin_ek":"Gölge daveti: her şey tohum halinde güzel; ama bazılarını ekmek de gerekir.","paylasim":"Fazım Yeni Ay — niyet tohumuyum."},"hilal":{"ad":"Büyüyen Hilal","tek_satir":"Sen bir ivmesin; niyetini eyleme döken ilk cesur adım.","kisa":"Hilal enerjisi büyüme ve umuttur — tohumu suladın, filiz verdi. İlerlemeyi, denemeyi seversin.","derin_ek":"Gölge daveti: büyürken acele etme; her filiz kendi hızında.","paylasim":"Fazım Büyüyen Hilal — cesur ilk adım."},"dolunay":{"ad":"Dolunay","tek_satir":"Sen doruk noktasısın; parlaklığın ve duygu yoğunluğun tam.","kisa":"Dolunay enerjisi doluluk ve ifadedir — görünür, parlak, yoğun. Zirveyi, açığa çıkmayı, paylaşmayı seversin.","derin_ek":"Gölge daveti: her zaman dolu parlamak zorunda değilsin; solmak da döngünün parçası.","paylasim":"Fazım Dolunay — parlaklığım tam."},"sonhilal":{"ad":"Solan Ay","tek_satir":"Sen bir bilgeliksin; bırakmayı ve sadeleşmeyi bilen enerji.","kisa":"Solan ay enerjisi olgunluk ve bırakıştır — hasadı topladın, fazlalığı bırakıyorsun. Dinlenmeyi, sindirmeyi bilirsin.","derin_ek":"Gölge daveti: bırakmak güzel; ama bazı şeyleri tutmaya da izin var.","paylasim":"Fazım Solan Ay — bırakmayı bilirim."}},"sorular":[{"soru":"Hayatında şu an hangi enerji baskın?","secenekler":[{"metin":"Yeni bir şey başlatma isteği","p":"yeniay"},{"metin":"Bir şeyi büyütme, ilerletme","p":"hilal"},{"metin":"Zirvede, her şey açık","p":"dolunay"},{"metin":"Bırakma, dinlenme, sadeleşme","p":"sonhilal"}]},{"soru":"Bir hedefe nasıl yaklaşırsın?","secenekler":[{"metin":"Hayal eder, niyet ederim","p":"yeniay"},{"metin":"Adım adım ilerlerim","p":"hilal"},{"metin":"Tüm enerjimle üstüne giderim","p":"dolunay"},{"metin":"Gözden geçirir, gereksizi atarım","p":"sonhilal"}]},{"soru":"Duyguların genelde nasıl?","secenekler":[{"metin":"Sakin, içe dönük, kıpırtılı","p":"yeniay"},{"metin":"Umutlu, artan","p":"hilal"},{"metin":"Yoğun, dolu, taşkın","p":"dolunay"},{"metin":"Dingin, sindirilmiş","p":"sonhilal"}]},{"soru":"İdeal bir akşam?","secenekler":[{"metin":"Yeni planlar kurmak","p":"yeniay"},{"metin":"Bir işi ilerletmek","p":"hilal"},{"metin":"Sevdiklerimle parlamak","p":"dolunay"},{"metin":"Sadeleşmek, temizlemek","p":"sonhilal"}]},{"soru":"Neyi kolay yaparsın?","secenekler":[{"metin":"Hayal kurmak","p":"yeniay"},{"metin":"Motive olmak","p":"hilal"},{"metin":"Kendini ifade etmek","p":"dolunay"},{"metin":"Bırakmak","p":"sonhilal"}]},{"soru":"Bir dönem bittiğinde?","secenekler":[{"metin":"Hemen yenisini hayal ederim","p":"yeniay"},{"metin":"Öğrendiklerimle ilerlerim","p":"hilal"},{"metin":"Kutlar, kapatırım","p":"dolunay"},{"metin":"Sindirir, dinlenirim","p":"sonhilal"}]},{"soru":"Seni en iyi anlatan?","secenekler":[{"metin":"'Henüz başlıyorum'","p":"yeniay"},{"metin":"'Yolculuktayım'","p":"hilal"},{"metin":"'Tam buradayım'","p":"dolunay"},{"metin":"'Bırakıyorum, hafifliyorum'","p":"sonhilal"}]},{"soru":"Ayın hangi hali sana en tanıdık?","secenekler":[{"metin":"Görünmez ama var olan","p":"yeniay"},{"metin":"Usulca büyüyen ışık","p":"hilal"},{"metin":"Gökyüzünü dolduran","p":"dolunay"},{"metin":"Yavaşça çekilen","p":"sonhilal"}]}]}},{"quiz_id":"ay7-hayvan","ay":7,"title":"İç Hayvanın","data":{"_meta":{"puanlama":"p +2, s +1; Baskın+Yükselen. Eşitlikte son soru.","durum":"TASLAK-ONAYLI; TR polisaj checklist.","hassasiyet":"'Kalıp değil ayna' açılışı ortak; güçlendirici çerçeve. Etiket: sembolik · eğlence amaçlı.","belge":"quiz-ay7-hayvan","surum":"v0.1","tarih":"2026-07-05","duyarlilik_ozel":"'Spirit animal' / kültürel-totem dili KULLANILMADI (tasarım dosyası kuralı). Çerçeve: 'sende hangi hayvan enerjisi baskın' — kişilik-metafor, ruhani/kültürel iddia değil. Etiket: sembolik · eğlence amaçlı.","gating":"Free: hayvan+kisa. Pro: derin_ek + astro overlay."},"acilis_metni":"Bunlar kalıp değil, ayna — bu hayvanların enerjisi sende. Bugün hangisi içinde dolaşıyor, ona bakıyoruz.","sonuc_sablonu":"Baskın: {A} · Yükselen: {B} — {A_tek_satir}","arketipler":{"kurt":{"ad":"Kurt","tek_satir":"Bağımsız ama sadık; hem yalnız yürür hem sürünü korursun.","kisa":"Kurt enerjisi sadakat ve özgürlüktür — güçlü sezgi, derin bağ, net sınır. Ailene bağlı ama kimseye bağımlı değilsin.","derin_ek":"Gölge daveti: yalnız yürüyebilirsin; ama sürüye yaslanmak zayıflık değil.","paylasim":"Hayvanım Kurt — bağımsız ama sadık."},"kedi":{"ad":"Kedi","tek_satir":"Zarif ve bağımsız; sevgini de alanını da kendin seçersin.","kisa":"Kedi enerjisi özerklik ve zarafettir — seçici, gizemli, öz-yeterli. Yakınlığını hak edene verirsin.","derin_ek":"Gölge daveti: mesafe seni korur; ama bazen yaklaşmak da güzeldir.","paylasim":"Hayvanım Kedi — alanımı kendim seçerim."},"kelebek":{"ad":"Kelebek","tek_satir":"Dönüşümün ustası; her evreyi güzelliğe çevirirsin.","kisa":"Kelebek enerjisi dönüşüm ve hafifliktir — değişimden korkmaz, güzelliğe uçarsın. Her son, senin için yeni bir kanat.","derin_ek":"Gölge daveti: uçmak güzel; ama bazen bir çiçekte de dinlen.","paylasim":"Hayvanım Kelebek — dönüşümün ustası."},"baykus":{"ad":"Baykuş","tek_satir":"Gecenin bilgesi; görünmeyeni görür, sessizce bilirsin.","kisa":"Baykuş enerjisi bilgelik ve sezgidir — sakin gözlem, derin kavrayış. Konuşmadan önce anlar, gölgede görürsün.","derin_ek":"Gölge daveti: her şeyi bilmek zorunda değilsin; bilmemek de dinlendirir.","paylasim":"Hayvanım Baykuş — gecenin bilgesi."},"geyik":{"ad":"Geyik","tek_satir":"Nazik ama tetikte; yumuşaklığın bir zayıflık değil, zarafet.","kisa":"Geyik enerjisi nezaket ve uyanıklıktır — narin, sezgili, zarif. Sertliğe ihtiyacın yok; yumuşaklığın gücün.","derin_ek":"Gölge daveti: tetikte olmak korur; ama bazen gardını indirip otlağın tadını çıkar.","paylasim":"Hayvanım Geyik — yumuşaklığım zarafetim."},"tilki":{"ad":"Tilki","tek_satir":"Zeki ve uyanık; her durumda kıvrak bir yol bulursun.","kisa":"Tilki enerjisi zekâ ve uyumdur — kurnaz değil akıllı, esnek, çözüm odaklı. Kapalı kapıya pencere bulursun.","derin_ek":"Gölge daveti: her şeyi tek başına çözmek zorunda değilsin; yardım istemek de zekâ.","paylasim":"Hayvanım Tilki — her zaman bir yol bulurum."},"kugu":{"ad":"Kuğu","tek_satir":"Sakin yüzeyde zarafet, altta güçlü kürek; zarafetin emek ürünü.","kisa":"Kuğu enerjisi zarafet ve iç güçtür — dışarıda dingin, içeride kararlı. Görünen sükûnetin, görünmez emeğinden gelir.","derin_ek":"Gölge daveti: hep zarif görünmek yorar; altta kürek çektiğini paylaşmak da güç.","paylasim":"Hayvanım Kuğu — sakin yüzey, güçlü kürek."}},"sorular":[{"soru":"Yeni bir ortama girince?","secenekler":[{"metin":"Kenarda gözlemlerim","p":"geyik","s":"baykus"},{"metin":"Kendi alanımı bulurum","p":"kugu","s":"kedi"},{"metin":"Hızla uyum sağlarım","p":"tilki"},{"metin":"Sakin ama tetikte dururum","p":"geyik"}]},{"soru":"Arkadaşlıkta sen?","secenekler":[{"metin":"Az ama derin bağ","p":"kugu","s":"kurt"},{"metin":"Bağımsız ama sıcak","p":"kedi"},{"metin":"Herkesle uyumlu","p":"kelebek"},{"metin":"Sadık ve koruyucu","p":"kurt","s":"kugu"}]},{"soru":"Zorlukta stratejin?","secenekler":[{"metin":"Sabırla gözler, doğru anı beklerim","p":"baykus"},{"metin":"Kıvrak bir çözüm bulurum","p":"tilki"},{"metin":"Dönüştürür, fırsata çeviririm","p":"kelebek"},{"metin":"Sakin kalır, içten güçlenirim","p":"kugu"}]},{"soru":"Seni ne tanımlar?","secenekler":[{"metin":"Sadakat","p":"kurt"},{"metin":"Bağımsızlık","p":"kedi"},{"metin":"Dönüşüm","p":"kelebek"},{"metin":"Bilgelik","p":"baykus"}]},{"soru":"İdeal anın?","secenekler":[{"metin":"Sürümle/ailemle","p":"kurt"},{"metin":"Tek başıma, huzurlu","p":"kedi"},{"metin":"Yeni bir yere uçarken","p":"kelebek"},{"metin":"Gece, sessizlikte","p":"baykus"}]},{"soru":"İnsanlar sana ne için gelir?","secenekler":[{"metin":"Korunmaya, güvene","p":"kurt"},{"metin":"Bilgece bir bakışa","p":"baykus"},{"metin":"Bir çözüme","p":"tilki"},{"metin":"Sakinleşmeye","p":"geyik"}]},{"soru":"Değişim geldiğinde?","secenekler":[{"metin":"Kanat açarım","p":"kelebek"},{"metin":"Uyum sağlarım","p":"tilki"},{"metin":"Sağlam dururum","p":"kurt"},{"metin":"Zarafetle akarım","p":"kugu"}]},{"soru":"Gece uyanıksan ne yaparsın?","secenekler":[{"metin":"Düşünür, sezerim","p":"baykus"},{"metin":"Sessizce dolaşırım","p":"kedi"},{"metin":"Rüyalara dalarım","p":"geyik"},{"metin":"Planımı kurarım","p":"tilki"}]}]}},{"quiz_id":"ay8-ickahraman","ay":8,"title":"İç Kahramanın","data":{"_meta":{"puanlama":"p +2, s +1; Baskın+Yükselen.","durum":"TASLAK-ONAYLI; TR polisaj checklist.","belge":"quiz-ay8-ickahraman","surum":"v0.1","tarih":"2026-07-05","KATMAN":"A-BİLİM (yumuşak). Jung'un arketip kuramından ESİNLENMİŞTİR. Kavramlar (arketip, gölge) kamu malı/genel kültür; klinik test değil, sembolik öz-yansıtma.","ic_kaynak":"Jungian arketipler + popüler '12 arketip' geleneği (Pearson/Mark & Pearson çerçevesi genel kültür). 12'den 7 seçildi (mobil + marka uyumu); metinler özgün. 'Esinlenen' ibaresi zorunlu.","gating":"Free: baskın/yükselen+kisa. Pro: derin_ek (gölge çalışması) + astro overlay + yıl haritası.","hassasiyet":"'Gölge daveti' yapıcı çerçevede (patoloji değil, bütünleşme). 'Kalıp değil ayna.' Etiket: sembolik · eğlence amaçlı."},"acilis_metni":"Bunlar kalıp değil, ayna — bu kahramanların hepsi sende yaşar. Bugün hangisi öne çıkıyor, ona bakıyoruz.","sonuc_sablonu":"Baskın: {A} · Yükselen: {B} — {A_tek_satir}","arketipler":{"masum":{"ad":"Masum","tek_satir":"İyimserliğin ve saflığın gücün; dünyaya umutla bakarsın.","kisa":"Masum arketipi güven ve umuttur — iyiyi görme, sadelik, inanç. Karmaşayı değil huzuru ararsın.","derin_ek":"Gölge daveti: dünyanın gölgelerini de görmek saflığı yok etmez, olgunlaştırır.","paylasim":"İç kahramanım: Masum — umutla bakarım."},"kasif":{"ad":"Kâşif","tek_satir":"Özgürlük ve keşif seni çağırır; sınırlar sana dar gelir.","kisa":"Kâşif arketipi özgürlük ve otantikliktir — yeni ufuklar, kendi yolu, bağımsızlık. Rutin seni boğar.","derin_ek":"Gölge daveti: sürekli aramak bazen huzursuzluktur; bazı yerler kalmaya değer.","paylasim":"İç kahramanım: Kâşif — ufuk beni çağırır."},"bilge":{"ad":"Bilge","tek_satir":"Hakikat ve anlayış peşindesin; bilgi senin ışığın.","kisa":"Bilge arketipi bilgelik ve hakikattir — anlama, öğrenme, derinlik. Yüzeysel değil, öze inersin.","derin_ek":"Gölge daveti: her şeyi anlamak zorunda değilsin; bazen yaşamak, bilmekten öğretir.","paylasim":"İç kahramanım: Bilge — hakikat ışığım."},"yaratici":{"ad":"Yaratıcı","tek_satir":"Hayal gücü ve ifade senin alanın; zihnindekini var edersin.","kisa":"Yaratıcı arketipi hayal ve ifadedir — özgünlük, vizyon, üretim. Var olmayanı hayal eder, gerçeğe dökersin.","derin_ek":"Gölge daveti: mükemmeliyet bazen üretimi durdurur; 'yeterince iyi' de bir sanat.","paylasim":"İç kahramanım: Yaratıcı — hayalimi var ederim."},"sefkatli":{"ad":"Şefkatli","tek_satir":"Bakım ve koruma senin doğan; sevginle sararsın.","kisa":"Şefkatli arketipi bakım ve cömertliktir — koruma, besleme, fedakârlık. Başkalarının iyiliği seni motive eder.","derin_ek":"Gölge daveti: herkese bakarken kendini ihmal etme; senin de bakıma hakkın var.","paylasim":"İç kahramanım: Şefkatli — sevgiyle sararım."},"asik":{"ad":"Âşık","tek_satir":"Tutku ve bağ senin dilin; güzellik ve yakınlık peşindesin.","kisa":"Âşık arketipi tutku ve bağlanmadır — yakınlık, güzellik, adanmışlık. Derin bağlar ve estetik seni canlandırır.","derin_ek":"Gölge daveti: sevgide kendini kaybetme; bütün kalırken bağ kurmak mümkün.","paylasim":"İç kahramanım: Âşık — bağ benim dilim."},"sihirbaz":{"ad":"Sihirbaz","tek_satir":"Dönüşüm ve vizyon senin gücün; gerçekliği değiştirebilirsin.","kisa":"Sihirbaz arketipi dönüşüm ve farkındalıktır — değişim yaratır, görünmeyeni okur, yeni bakışlar açarsın. Değişimin katalizörüsün.","derin_ek":"Gölge daveti: her şeyi dönüştürmek zorunda değilsin; bazı şeyler olduğu gibi güzel.","paylasim":"İç kahramanım: Sihirbaz — dönüşümün katalizörü."}},"sorular":[{"soru":"Seni en çok ne motive eder?","secenekler":[{"metin":"Özgürlük ve keşif","p":"kasif"},{"metin":"Anlamak ve öğrenmek","p":"masum","s":"bilge"},{"metin":"Yaratmak, ifade etmek","p":"yaratici"},{"metin":"Başkalarına bakmak","p":"sefkatli"}]},{"soru":"Dünyaya bakışın?","secenekler":[{"metin":"Temelde iyi ve umut dolu","p":"masum"},{"metin":"Keşfedilecek bir macera","p":"kasif"},{"metin":"Çözülecek bir bilmece","p":"asik","s":"bilge"},{"metin":"Güzelleştirilecek bir tuval","p":"yaratici"}]},{"soru":"İnsanlar en çok ne için kapını çalar?","secenekler":[{"metin":"Bilgeliğe, tavsiyeye","p":"bilge"},{"metin":"Şefkate, desteğe","p":"sefkatli"},{"metin":"İlhama, yaratıcılığa","p":"yaratici"},{"metin":"Dönüşüme, yeni bakışa","p":"sihirbaz"}]},{"soru":"Bir ilişkide en çok ne ararsın?","secenekler":[{"metin":"Derin tutku ve bağ","p":"asik"},{"metin":"Özgürlük ve alan","p":"kasif"},{"metin":"Güven ve sadakat","p":"sefkatli"},{"metin":"Birlikte büyüme","p":"sihirbaz"}]},{"soru":"Boş zamanında?","secenekler":[{"metin":"Yeni yerler keşfederim","p":"kasif"},{"metin":"Okur, araştırırım","p":"bilge"},{"metin":"Bir şey yaratırım","p":"yaratici"},{"metin":"Sevdiklerimle ilgilenirim","p":"sefkatli"}]},{"soru":"Zorlukta gücün nereden gelir?","secenekler":[{"metin":"İnancım ve umudum","p":"masum"},{"metin":"Bilgim ve mantığım","p":"bilge"},{"metin":"Sevgim ve bağlarım","p":"asik"},{"metin":"Dönüştürme yeteneğim","p":"sihirbaz"}]},{"soru":"Seni en iyi anlatan?","secenekler":[{"metin":"'Dünya güzel bir yer'","p":"masum"},{"metin":"'Daha fazlası var'","p":"kasif"},{"metin":"'Anlamak istiyorum'","p":"bilge"},{"metin":"'Değiştirebilirim'","p":"sihirbaz"}]},{"soru":"Hayatta en çok ne yaratmak istersin?","secenekler":[{"metin":"Güzellik ve sanat","p":"yaratici"},{"metin":"Bağ ve sevgi","p":"asik"},{"metin":"Bilgi ve anlayış","p":"bilge"},{"metin":"Dönüşüm ve yenilenme","p":"sihirbaz"}]}]}},{"quiz_id":"ay9-mevsim","ay":9,"title":"İç Mevsimin","data":{"_meta":{"puanlama":"p +2, s +1; Baskın+Yükselen. Eşitlikte son soru.","durum":"TASLAK-ONAYLI; TR polisaj checklist.","hassasiyet":"'Kalıp değil ayna' açılışı ortak; güçlendirici çerçeve. Etiket: sembolik · eğlence amaçlı.","belge":"quiz-ay9-mevsim","surum":"v0.1","tarih":"2026-07-05","ozel_sinerji":"Mevsim-haritası/parlama modeliyle tematik uyum + mevsim→bitki köprüsü. 4 mevsim arketipi.","gating":"Free: mevsim+kisa+bitki. Pro: derin_ek + gerçek mevsimle uyum + astro overlay."},"acilis_metni":"Bunlar kalıp değil, ayna — dört mevsim de içinde yaşar. Bugün hangisi sende hüküm sürüyor, ona bakıyoruz.","sonuc_sablonu":"Baskın: {A} · Yükselen: {B} — {A_tek_satir} (Senin bitkin: {A_bitki}.)","arketipler":{"ilkbahar":{"ad":"İlkbahar Ruhu","tek_satir":"Sen yenilenmenin ruhusun; her şeyde yeniden doğuşu görürsün.","kisa":"İlkbahar enerjisi tazelik ve umuttur — taze başlangıçlar, filizlenme, iyimserlik. Yeniyi sen açarsın.","derin_ek":"Gölge daveti: her şey yeni ve heyecanlı; ama bitirmek de büyümenin parçası.","bitki":"menekse","paylasim":"Mevsimim İlkbahar — yenilenmenin ruhu."},"yaz":{"ad":"Yaz Ruhu","tek_satir":"Sen bolluğun ta kendisisin; enerjin ve neşen çevrene taşar.","kisa":"Yaz enerjisi coşku ve doluluktur — canlı, sıcak, cömert. Hayatı dolu dolu, yüksek sesle yaşarsın.","derin_ek":"Gölge daveti: hep parlamak yorar; gölgeye çekilmek de dinlendirir.","bitki":"aynisefa","paylasim":"Mevsimim Yaz — enerjim taşar."},"sonbahar":{"ad":"Sonbahar Ruhu","tek_satir":"Sen olgun bir güzelliksin; bırakmayı ve şükretmeyi bilirsin.","kisa":"Sonbahar enerjisi olgunluk ve zarafettir — hasat, minnet, güzel bir bırakış. Derinliği ve dönüşümü kucaklarsın.","derin_ek":"Gölge daveti: bırakmakta ustasın; ama kış için birkaç şey saklamak da bilgeliktir.","bitki":"ceviz","paylasim":"Mevsimim Sonbahar — olgun bir güzellik."},"kis":{"ad":"Kış Ruhu","tek_satir":"Sen derin bir dinginliksin; sessizlikte güç toplarsın.","kisa":"Kış enerjisi içe dönüş ve dinlenmedir — sükûnet, sabır, derinlik. Sessizlikte kök salar, sonra dönersin.","derin_ek":"Gölge daveti: içe çekilmek onarır; ama kapıyı ilkbahara da arala.","bitki":"kediotu","paylasim":"Mevsimim Kış — sessizlikte güç toplarım."}},"sorular":[{"soru":"Hayata bakışın?","secenekler":[{"metin":"Her gün yeni bir başlangıç","p":"ilkbahar"},{"metin":"Dolu dolu yaşanmalı","p":"yaz"},{"metin":"Her şeyin bir mevsimi var","p":"sonbahar"},{"metin":"Sessizlikte anlam bulunur","p":"kis"}]},{"soru":"İdeal bir gün?","secenekler":[{"metin":"Taze, hareketli, yeni","p":"ilkbahar"},{"metin":"Güneşli, sosyal, canlı","p":"yaz"},{"metin":"Sıcak içecek, kitap, huzur","p":"sonbahar"},{"metin":"Battaniye, sessizlik, iç dünya","p":"kis"}]},{"soru":"Enerjin nasıl?","secenekler":[{"metin":"Filizlenen, meraklı","p":"ilkbahar"},{"metin":"Yüksek, taşan","p":"yaz"},{"metin":"Dingin, olgun","p":"sonbahar"},{"metin":"Derin, sakin","p":"kis"}]},{"soru":"Değişimle aran?","secenekler":[{"metin":"Bayılırım, yeniyi severim","p":"ilkbahar"},{"metin":"Heyecanla karşılarım","p":"yaz"},{"metin":"Zarafetle kabul ederim","p":"sonbahar"},{"metin":"Yavaşça, içe dönerek","p":"kis"}]},{"soru":"Seni ne besler?","secenekler":[{"metin":"Yeni deneyimler","p":"ilkbahar"},{"metin":"İnsanlar, kahkaha","p":"yaz"},{"metin":"Anlam, derinlik","p":"sonbahar"},{"metin":"Yalnızlık, dinlenme","p":"kis"}]},{"soru":"Zor zamanda?","secenekler":[{"metin":"Yeni bir kapı ararım","p":"ilkbahar"},{"metin":"Enerjimi yükseltirim","p":"yaz"},{"metin":"Kabul eder, sindiririm","p":"sonbahar"},{"metin":"İçime çekilir, beklerim","p":"kis"}]},{"soru":"Seni en iyi anlatan?","secenekler":[{"metin":"'Yeniden başlıyorum'","p":"ilkbahar"},{"metin":"'Şu an yaşıyorum'","p":"yaz"},{"metin":"'Minnettarım'","p":"sonbahar"},{"metin":"'Dinleniyorum'","p":"kis"}]},{"soru":"Doğada seni ne çeker?","secenekler":[{"metin":"İlk açan çiçek","p":"ilkbahar"},{"metin":"Öğle güneşi","p":"yaz"},{"metin":"Düşen yapraklar","p":"sonbahar"},{"metin":"Karla kaplı sessizlik","p":"kis"}]}]}},{"quiz_id":"ay10-cadi","ay":10,"title":"Cadı Türün","data":{"_meta":{"belge":"quiz-ay10-cadi","surum":"v0.1","tarih":"2026-07-05","ozel_sinerji":"SOFT WITCHERY ÇEKİRDEĞİ + MODÜL KÖPRÜSÜ: her cadı türü bir modüle bağlanır (Mutfak→döngü-beslenme, Yeşil→herbaryum, Ay→kozmos, Deniz→breathwork, Kozmik→keşif, Kristal→skincare, Eşik→journal). Sonuç ekranı kullanıcıyı 'senin modülün'e yönlendirir → tüm uygulamaya cross-sell.","hassasiyet":"'Cadı' güçlendirici/estetik çerçevede; okült/inanç iddiası değil, kişilik-estetik kimliği. 'Kalıp değil ayna' açılışı ortak. Etiket: sembolik · eğlence amaçlı.","puanlama":"p +2, s +1; Baskın+Yükselen.","gating":"Free: baskın/yükselen+kisa+modül köprüsü. Pro: derin_ek + astro overlay.","durum":"TASLAK-ONAYLI; TR polisaj checklist."},"acilis_metni":"Bunlar kalıp değil, ayna — hepsi sende var. Hangi cadı bugün sende uyanık, ona bakıyoruz.","sonuc_sablonu":"Baskın: {A} · Yükselen: {B} — {A_tek_satir} (Senin köşen: {A_modul}.)","arketipler":{"mutfak":{"ad":"Mutfak Cadısı","tek_satir":"Büyün tencerede pişer; sıradan bir yemeği ritüele çevirirsin.","kisa":"Mutfak cadısı gündelik büyüdür — niyeti çorbaya, sevgiyi ekmeğe katarsın. Sihrin görkemli değil, besleyici.","derin_ek":"Gölge daveti: herkesi doyururken kendi tabağını unutma.","modul":"cycle-nutrition","paylasim":"Ben bir Mutfak Cadısıyım — büyüm tencerede pişer."},"yesil":{"ad":"Yeşil Cadı","tek_satir":"Toprakla konuşursun; bitkiler senin dilini bilir.","kisa":"Yeşil cadı doğanın çırağıdır — saksılar, tohumlar, kurutulmuş demetler. Büyün kökten ve yapraktan gelir.","derin_ek":"Gölge daveti: her şeyi büyütmek istersin; bazen bir şeyi solmaya bırakmak da bahçıvanlıktır.","modul":"herbaryum","paylasim":"Ben bir Yeşil Cadıyım — bitkiler dilimi bilir."},"ay":{"ad":"Ay Cadısı","tek_satir":"Ritmin gökten gelir; dolunayda dolar, yeniayda yenilenirsin.","kisa":"Ay cadısı döngülerle yaşar — niyetlerini fazlara göre kurar, duygularını ayla okur. Sezgin en güçlü aracın.","derin_ek":"Gölge daveti: her duyguyu aya bağlama; bazıları sadece senin.","modul":"kozmos","paylasim":"Ben bir Ay Cadısıyım — ritmim gökten gelir."},"deniz":{"ad":"Deniz Cadısı","tek_satir":"Duyguların gelgit gibi; derinliğin hem gücün hem sığınağın.","kisa":"Deniz cadısı suyun büyüsüdür — tuz, kabuk, gözyaşı ve dalga. Akışı da bırakışı da bilirsin.","derin_ek":"Gölge daveti: derin sular güzel; ama ara sıra kıyıya da çık.","modul":"breathwork","paylasim":"Ben bir Deniz Cadısıyım — duygularım gelgit gibi."},"kozmik":{"ad":"Kozmik Cadı","tek_satir":"Yıldızlar senin haritan; büyün gezegenlerin dilinde yazılı.","kisa":"Kozmik cadı gök bilgesidir — transitler, dekanlar, yıldız işaretleri. Büyük resmi ve zamanlamayı okursun.","derin_ek":"Gölge daveti: her şeyi yıldızlara sorma; bazen sadece hisset.","modul":"kesif","paylasim":"Ben bir Kozmik Cadıyım — haritam yıldızlarda."},"kristal":{"ad":"Kristal Cadısı","tek_satir":"Güzellikte güç bulursun; rengin ve ışığın dilinden anlarsın.","kisa":"Kristal cadı estetiğin ustasıdır — taşlar, renkler, ışık oyunları. Bir odanın havasını ilk bakışta sezer, güzellikle dönüştürürsün.","derin_ek":"Gölge daveti: dışarıyı düzenlerken içerini de dinle.","modul":"skincare","paylasim":"Ben bir Kristal Cadıyım — güzellikte güç bulurum."},"hedge":{"ad":"Eşik Cadısı","tek_satir":"İki dünyanın arasında yürürsün; rüya ile uyanıklık senin sınırında buluşur.","kisa":"Eşik cadısı sezgi gezginidir — rüyalar, içe yolculuk, sessiz bilme. Görünenin ötesini fark edersin.","derin_ek":"Gölge daveti: ötesini görmek güzel; ama buraya, şimdiye de kök sal.","modul":"journal","paylasim":"Ben bir Eşik Cadısıyım — iki dünyanın arasındayım."}},"sorular":[{"soru":"Evinde mutlaka bulunan şey?","secenekler":[{"metin":"Kurutulmuş bitki demetleri","p":"kristal","s":"yesil"},{"metin":"Baharat ve el yapımı karışımlar","p":"mutfak"},{"metin":"Ay takvimi / kristal takımı","p":"ay","s":"kristal"},{"metin":"Rüya günlüğü","p":"hedge"}]},{"soru":"Stresli bir günde ritüelin?","secenekler":[{"metin":"Niyetle bir yemek pişirmek","p":"mutfak"},{"metin":"Bitkilerimle ilgilenmek","p":"yesil"},{"metin":"Deniz/su sesi dinlemek","p":"deniz"},{"metin":"Mum yakıp içe dönmek","p":"hedge"}]},{"soru":"Seni en çok ne büyüler?","secenekler":[{"metin":"Dolunay","p":"kristal","s":"ay"},{"metin":"Yıldız haritaları","p":"kozmik"},{"metin":"Dalgaların sesi","p":"deniz"},{"metin":"Işığın kristalde kırılması","p":"kristal"}]},{"soru":"Bir niyeti nasıl güçlendirirsin?","secenekler":[{"metin":"Ay fazına göre zamanlarım","p":"ay"},{"metin":"Doğru günü yıldızlardan seçerim","p":"kozmik"},{"metin":"Toprağa bir tohum ekerim","p":"yesil"},{"metin":"Yemeğe niyet katarım","p":"mutfak"}]},{"soru":"İç dünyana nasıl bağlanırsın?","secenekler":[{"metin":"Rüyalarım ve iç yolculuklarım","p":"hedge"},{"metin":"Suyla, banyoyla arınarak","p":"deniz"},{"metin":"Cildime, bedenime bakarak","p":"kristal"},{"metin":"Ayı ve duygularımı izleyerek","p":"ay"}]},{"soru":"Favori atmosferin?","secenekler":[{"metin":"Buhar tüten bir mutfak","p":"mutfak"},{"metin":"Yeşilliğe boğulmuş bir oda","p":"yesil"},{"metin":"Ay ışıklı bir pencere kenarı","p":"ay"},{"metin":"Loş, mumlu, sessiz bir köşe","p":"hedge"}]},{"soru":"Bir arkadaşına nasıl destek olursun?","secenekler":[{"metin":"Sıcak bir yemek yaparım","p":"mutfak"},{"metin":"Bir demlik bitki çayı yapar, yanında otururum","p":"yesil"},{"metin":"'Gökyüzü ne diyor' der, birlikte bakarız","p":"kozmik"},{"metin":"Sadece dinlerim, hissederim","p":"deniz"}]},{"soru":"Gece göğünde gözün nereye gider?","secenekler":[{"metin":"Ayın evresine","p":"ay"},{"metin":"Gezegenlerin dizilişine","p":"kozmik"},{"metin":"Ayın sudaki yansımasına","p":"deniz"},{"metin":"Yıldızların ardındaki karanlığa","p":"hedge"}]}]}},{"quiz_id":"ay11-aura","ay":11,"title":"Aura Rengin","data":{"_meta":{"belge":"quiz-ay11-aura","surum":"v0.1","tarih":"2026-07-05","ozel_sinerji":"EN GÜÇLÜ GÖRSEL-PAYLAŞIM AYI: sonuç bir RENK (marka paletinden). Paylaşım kartı R1.5 hattında saf renk-alanı + aura adı → Instagram estetiğiyle birebir; sosyal fabrika çift kullanımı en yüksek. Renkler görsel tasarım kiti paletinden (marka tutarlılığı).","hassasiyet":"Aura estetik-kişilik çerçevesinde; enerji-okuma iddiası değil. 'Kalıp değil ayna' açılışı ortak. Etiket: sembolik · eğlence amaçlı.","puanlama":"p +2, s +1; Baskın+Yükselen (iki renk = aura gradyanı, görsel olarak güzel).","gating":"Free: aura + kisa + renk kartı. Pro: derin_ek + gradyan animasyonlu paylaşım + astro overlay.","not":"7 renk: 5'i palet (pudra yeşil/mavi/pembe/kavun/lila) + 2 türetme (inci beyazı, gül kurusu) paletle uyumlu. Hex'ler görsel kitle senkron; kesinleşince güncellenir.","durum":"TASLAK-ONAYLI; TR polisaj checklist."},"acilis_metni":"Bunlar kalıp değil, ayna — hepsi sende var. Bugün hangi renk çevrende parlıyor, ona bakıyoruz.","sonuc_sablonu":"Auran: {A} · İkincil ton: {B} — {A_tek_satir}","arketipler":{"pudra_yesil":{"ad":"Pudra Yeşil Aura","hex":"#CADBC8","tek_satir":"Denge ve tazelik yayarsın; yanında insanlar derin bir nefes almış gibi hisseder.","kisa":"Yeşil aura büyümenin ve kalbin rengidir — sakin, kucaklayıcı, dengeli. Yanında her şey serpilir gibi.","derin_ek":"Gölge daveti: herkesle ilgilenirken aynı özeni kendine de göster.","paylasim":"Auram Pudra Yeşil — denge ve tazelik yayarım."},"pudra_mavi":{"ad":"Pudra Mavi Aura","hex":"#C9D8E4","tek_satir":"Dinginlik ve berraklık taşırsın; sözlerin ortalığı yumuşatır.","kisa":"Mavi aura iletişim ve huzurdur — açık, dürüst, dingin. İnsanlar yanında rahatça konuşur.","derin_ek":"Gölge daveti: hep sakin görünmek zorunda değilsin; ara sıra fırtınan da görünsün.","paylasim":"Auram Pudra Mavi — dinginlik ve berraklık."},"pudra_pembe":{"ad":"Pudra Pembe Aura","hex":"#EBD3D6","tek_satir":"Sevgi ve şefkat yayarsın; kalbin herkese açık.","kisa":"Pembe aura sevgi ve nazikliktir — sıcak, kucaklayıcı, romantik. Yanında sevilmek kolaydır.","derin_ek":"Gölge daveti: sevgini dağıtırken kendine ayırmayı unutma.","paylasim":"Auram Pudra Pembe — sevgi ve şefkat yayarım."},"kavun":{"ad":"Kavun İçi Aura","hex":"#F6D9C2","tek_satir":"Sıcaklık ve yaratıcılık saçarsın; enerjin bulaşıcı.","kisa":"Kavun aura neşe ve yaratıcılıktır — canlı, sıcak, ilham verici. Girdiğin ortam renklenir.","derin_ek":"Gölge daveti: hep parlamak yorar; sönük günlerine de hakkın var.","paylasim":"Auram Kavun İçi — sıcaklık ve yaratıcılık."},"lila":{"ad":"Lila Aura","hex":"#D6C9E0","tek_satir":"Sezgi ve gizem taşırsın; görünmeyeni sezersin.","kisa":"Lila aura sezgi ve derinliktir — bilge, gizemli, içe dönük. Satır aralarını okursun.","derin_ek":"Gölge daveti: sezgin güçlü; ama bazen mantığın da söz alsın.","paylasim":"Auram Lila — sezgi ve gizem taşırım."},"inci":{"ad":"İnci Beyazı Aura","hex":"#F4EFEA","tek_satir":"Saflık ve tazelik yayarsın; yeni başlangıçların rengisin.","kisa":"İnci aura tazelik ve potansiyeldir — berrak, duru, yeni. Her günü temiz bir sayfa gibi karşılarsın.","derin_ek":"Gölge daveti: her şeyi temiz tutmak yorar; biraz dağınıklık da hayatın rengi.","paylasim":"Auram İnci Beyazı — saflık ve tazelik."},"gul_kurusu":{"ad":"Gül Kurusu Aura","hex":"#C99DA3","tek_satir":"Olgun bir zarafet taşırsın; sıcaklık ve derinliği birleştirirsin.","kisa":"Gül kurusu aura olgunluk ve şefkatli güçtür — köklü, zarif, dengeli. Hem sıcak hem sağlamsın.","derin_ek":"Gölge daveti: güçlü durmak zorunda değilsin her an; kırılganlığın da güzel.","paylasim":"Auram Gül Kurusu — olgun bir zarafet."}},"sorular":[{"soru":"Sabah uyandığında ilk hissin genelde?","secenekler":[{"metin":"Sakin bir denge","p":"gul_kurusu","s":"pudra_yesil"},{"metin":"Berrak bir zihin","p":"inci","s":"pudra_mavi"},{"metin":"İçten bir sıcaklık","p":"pudra_pembe"},{"metin":"Yaratıcı bir kıpırtı","p":"inci","s":"kavun"}]},{"soru":"İnsanlar yanında ne hisseder?","secenekler":[{"metin":"Huzur, güven","p":"pudra_mavi","s":"pudra_yesil"},{"metin":"Sevildiklerini","p":"pudra_pembe"},{"metin":"Enerji, neşe","p":"gul_kurusu","s":"kavun"},{"metin":"Merak, gizem","p":"lila"}]},{"soru":"Hangi ortam seni doldurur?","secenekler":[{"metin":"Yeşil, doğal, ferah","p":"pudra_yesil"},{"metin":"Sakin, düzenli, açık","p":"pudra_mavi"},{"metin":"Sıcak, canlı, kalabalık","p":"kavun"},{"metin":"Loş, mistik, sessiz","p":"lila"}]},{"soru":"Zor bir anda kendini nasıl toparlarsın?","secenekler":[{"metin":"Doğaya, yeşile dönerim","p":"pudra_yesil"},{"metin":"Sevdiklerime sarılırım","p":"pudra_pembe"},{"metin":"Yaratıcı bir şeye dalarım","p":"kavun"},{"metin":"İçime çekilir, sezgime güvenirim","p":"lila"}]},{"soru":"Seni en iyi anlatan renk hissi?","secenekler":[{"metin":"Taze bir başlangıç","p":"inci"},{"metin":"Olgun bir sıcaklık","p":"gul_kurusu"},{"metin":"Sakin bir deniz","p":"pudra_mavi"},{"metin":"Yumuşak bir şefkat","p":"pudra_pembe"}]},{"soru":"Bir odaya girdiğinde ne değişir?","secenekler":[{"metin":"Ortam sakinleşir","p":"pudra_mavi"},{"metin":"Ortam ısınır","p":"kavun"},{"metin":"İnsanlar rahatlar","p":"pudra_pembe"},{"metin":"Bir merak dalgası yayılır","p":"lila"}]},{"soru":"Ruhunu en çok ne besler?","secenekler":[{"metin":"Büyütmek, yeşertmek","p":"pudra_yesil"},{"metin":"Temizlik, tazelik, düzen","p":"inci"},{"metin":"Derinlik ve olgunluk","p":"gul_kurusu"},{"metin":"İlham ve yaratım","p":"kavun"}]},{"soru":"Işığın nasıl?","secenekler":[{"metin":"Yumuşak yeşil bir parıltı","p":"pudra_yesil"},{"metin":"Berrak mavi bir aydınlık","p":"pudra_mavi"},{"metin":"Sıcak turuncu bir kor","p":"kavun"},{"metin":"Derin mor bir hâle","p":"lila"}]}]}},{"quiz_id":"ay12-degerler","ay":12,"title":"Değerler Pusulan","data":{"_meta":{"puanlama":"p +2, s +1; Baskın+Yükselen.","durum":"TASLAK-ONAYLI; TR polisaj checklist.","belge":"quiz-ay12-degerler","surum":"v0.1","tarih":"2026-07-05","KATMAN":"A-BİLİM (yumuşak). Schwartz Temel İnsani Değerler kuramından ESİNLENMİŞTİR. Klinik/doğrulanmış envanter DEĞİL; sembolik yıl-kapanışı yansıtması.","ic_kaynak":"Schwartz değerler dairesi (genel akademik çerçeve); 7 değere sadeleştirildi, metinler özgün. 'Esinlenen' ibaresi zorunlu.","yil_kapanisi":"12. ay = yıl kapanışı teması: 'gelecek yıl neye alan açacaksın'. Rotasyonun finali; bir sonraki yıla köprü.","gating":"Free: baskın/yükselen değer+kisa. Pro: derin_ek (bu yıla soru) + astro overlay + yıllık değer-yolculuğu özeti.","hassasiyet":"Değerler hiyerarşik/yargısal DEĞİL sunulur (hiçbir değer 'daha iyi'). 'Kalıp değil ayna.' Etiket: sembolik · eğlence amaçlı."},"acilis_metni":"Yıl kapanıyor. Bu bir test değil, bir ayna — pusulanın gelecek yıl nereyi gösterdiğine bakıyoruz.","sonuc_sablonu":"Pusulan: {A} · Yükselen: {B} — {A_tek_satir}","arketipler":{"ozgurluk":{"ad":"Özgürlük","tek_satir":"Kendi yolunu çizmek senin için her şeyden değerli.","kisa":"Özerklik ve özgür seçim senin pusulan — bağımsızlık, kendi kararların, sınırsızlık. Gelecek yıl daha çok kendi ritminde yaşamak isteyebilirsin.","derin_ek":"Bu yıla soru: özgürlüğü bağlardan kaçış olarak mı, kendini gerçekleştirme olarak mı yaşıyorsun?","paylasim":"Değerim: Özgürlük — kendi yolumu çizerim."},"baglilik":{"ad":"Bağlılık","tek_satir":"Sevdiklerinle derin bağlar senin en büyük zenginliğin.","kisa":"Yakınlık ve aidiyet senin pusulan — aile, dostluk, sadakat. Gelecek yıl bağlarına daha çok zaman ayırmak isteyebilirsin.","derin_ek":"Bu yıla soru: bağlarına verdiğin emeği kendine de veriyor musun?","paylasim":"Değerim: Bağlılık — bağlarım zenginliğim."},"basari":{"ad":"Başarı","tek_satir":"Bir şeyi ustalıkla yapmak ve iz bırakmak seni ateşler.","kisa":"Yetkinlik ve etki senin pusulan — hedefler, ustalık, katkı. Gelecek yıl anlamlı bir başarıya yönelmek isteyebilirsin.","derin_ek":"Bu yıla soru: başarıyı dışarının onayı için mi, kendi tatminin için mi arıyorsun?","paylasim":"Değerim: Başarı — iz bırakmak isterim."},"huzur":{"ad":"Huzur","tek_satir":"İç denge ve sükûnet senin için en yüksek değer.","kisa":"Denge ve dinginlik senin pusulan — sadelik, iç barış, uyum. Gelecek yıl huzuru koruyan sınırlar kurmak isteyebilirsin.","derin_ek":"Bu yıla soru: huzur bir kaçış mı, yoksa bilinçli bir seçim mi senin için?","paylasim":"Değerim: Huzur — iç dengem pusulam."},"merak":{"ad":"Merak","tek_satir":"Öğrenmek, keşfetmek, büyümek seni canlı tutar.","kisa":"Gelişim ve keşif senin pusulan — öğrenme, yeni deneyim, bilgelik. Gelecek yıl merakını besleyecek yollar arayabilirsin.","derin_ek":"Bu yıla soru: öğrendiklerini yaşamına da katıyor musun, yoksa sadece biriktiriyor musun?","paylasim":"Değerim: Merak — öğrenmek beni canlı tutar."},"sefkat_d":{"ad":"Şefkat","tek_satir":"Dünyaya ve insanlara iyilik katmak senin yolun.","kisa":"İyilik ve katkı senin pusulan — yardım, adalet, merhamet. Gelecek yıl şefkatini somut bir yola dökmek isteyebilirsin.","derin_ek":"Bu yıla soru: dünyaya verdiğin şefkatin bir damlasını kendine ayırıyor musun?","paylasim":"Değerim: Şefkat — iyilik katmak benim yolum."},"yaraticilik_d":{"ad":"Yaratıcılık","tek_satir":"Var olmayanı hayal edip yaratmak senin özün.","kisa":"İfade ve özgünlük senin pusulan — sanat, vizyon, üretim. Gelecek yıl yaratıcı sesini daha çok duyurmak isteyebilirsin.","derin_ek":"Bu yıla soru: yaratma dürtünü erteliyor musun, yoksa ona gerçekten zaman ayırıyor musun?","paylasim":"Değerim: Yaratıcılık — hayal edip yaratırım."}},"sorular":[{"soru":"Gelecek yıl için en çok neyi diliyorsun?","secenekler":[{"metin":"Daha çok özgürlük ve alan","p":"ozgurluk"},{"metin":"Daha derin bağlar","p":"baglilik"},{"metin":"Anlamlı bir başarı","p":"basari"},{"metin":"Daha çok iç huzur","p":"huzur"}]},{"soru":"Seni gerçekten mutlu eden?","secenekler":[{"metin":"Yeni şeyler öğrenmek","p":"merak"},{"metin":"Birine iyilik yapmak","p":"sefkat_d"},{"metin":"Bir şey yaratmak","p":"yaraticilik_d"},{"metin":"Sevdiklerimle olmak","p":"baglilik"}]},{"soru":"Bir kararı neye göre verirsin?","secenekler":[{"metin":"Bana özgürlük veriyor mu?","p":"ozgurluk"},{"metin":"İlişkilerime iyi geliyor mu?","p":"baglilik"},{"metin":"Beni ilerletiyor mu?","p":"basari"},{"metin":"Huzurumu koruyor mu?","p":"huzur"}]},{"soru":"Zamanını en çok neye ayırmak istersin?","secenekler":[{"metin":"Keşfe, öğrenmeye","p":"merak"},{"metin":"Yardıma, katkıya","p":"sefkat_d"},{"metin":"Yaratmaya","p":"yaraticilik_d"},{"metin":"Dinginliğe","p":"huzur"}]},{"soru":"Seni en çok ne tatmin eder?","secenekler":[{"metin":"Kendi kararlarımı vermek","p":"ozgurluk"},{"metin":"Bir şeyi ustalıkla bitirmek","p":"basari"},{"metin":"Birinin hayatına dokunmak","p":"sefkat_d"},{"metin":"Yeni bir şey kavramak","p":"merak"}]},{"soru":"Hayatında olmazsa olmaz?","secenekler":[{"metin":"Bağımsızlığım","p":"ozgurluk"},{"metin":"Sevdiklerim","p":"baglilik"},{"metin":"İç huzurum","p":"huzur"},{"metin":"Yaratma alanım","p":"yaraticilik_d"}]},{"soru":"Bir yıl sonra kendine ne demek istersin?","secenekler":[{"metin":"'Daha özgürüm'","p":"ozgurluk"},{"metin":"'Daha bağlıyım'","p":"baglilik"},{"metin":"'Daha başarılıyım'","p":"basari"},{"metin":"'Daha huzurluyum'","p":"huzur"}]},{"soru":"Dünyaya ne bırakmak istersin?","secenekler":[{"metin":"İyilik ve şefkat","p":"sefkat_d"},{"metin":"Bir eser, bir iz","p":"yaraticilik_d"},{"metin":"Bilgi ve ilham","p":"merak"},{"metin":"Sevgi ve bağ","p":"baglilik"}]}]}}]$wseed$::jsonb) as e
